import type { Drill } from "./types";

// Operations manager / mid drills, keyed by module slug — 25 per module.
// Pitched at a site or regional operations manager: process rollouts to front-line
// teams, KPI reviews upward, incident escalations, cross-site coordination, vendor
// negotiations, staffing calls, safety and quality comms. Merged into course.ts.
export const OPERATOR_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-ops-mid-01","level":"mid","profession":"operator","title":"The line-down escalation","scenario":"Packaging line 2 has been down for 40 minutes with a failed drive motor, and maintenance estimates two hours to repair. Today's outbound commitment of 1,800 cases is now at risk. Your draft to the site director opens with a timeline of how smoothly the morning started.","task":"Write a 2-3 sentence escalation that leads with what's down, the impact, and the restore estimate.","tips":["Sentence one: line 2 down, the cause, the ETA.","Name the business impact — the shipment at risk — immediately after.","The morning chronology adds nothing; cut it."],"focus":["structure","impact"],"placeholder":"Line 2 is down with a failed drive motor — estimated two hours to repair."},
    {"id":"lead-ops-mid-02","level":"mid","profession":"operator","title":"The overtime ask that buries itself","scenario":"You need the director to approve 12 hours of Saturday overtime to clear a 3,000-case backlog before Monday's promotional orders land. Your draft spends a paragraph explaining how the backlog built up before mentioning the request.","task":"Write a 2-3 sentence request that puts the ask and its cost in the first sentence.","tips":["Lead with the ask: 12 hours of OT Saturday, approximate cost.","How the backlog formed is one clause of support, not a paragraph.","End with the decision you need and by when."],"focus":["clarity","impact"]},
    {"id":"lead-ops-mid-03","level":"mid","profession":"operator","title":"The handover that hides the hazard","scenario":"You're handing the site to the night-shift duty manager. Conveyor 4 has jammed twice today and may jam again overnight — but your handover note opens with a calm recap of an otherwise smooth day.","task":"Rewrite the handover so the first line is the one thing they must watch and what to do.","tips":["First line: the live risk and the response.","Everything that went fine can follow, briefly.","If they read one line at 2 a.m., it should be this one."],"focus":["structure","precision"],"placeholder":"Watch conveyor 4 — it jammed twice today; if it jams again, call maintenance on-call before clearing it."},
    {"id":"lead-ops-mid-04","level":"mid","profession":"operator","title":"The KPI email that saves the headline","scenario":"After three weak weeks, on-time shipping recovered to 98.4% this week. Your weekly email to the site director narrates the week day by day, and the recovery only appears in the final paragraph.","task":"Write the opening 1-2 sentences so the recovery leads.","tips":["The number is the news — put it in sentence one.","Compare against the target or the prior weeks in the same breath.","The day-by-day story becomes optional support below."],"focus":["structure","concision"]},
    {"id":"lead-ops-mid-05","level":"mid","profession":"operator","title":"The supplier slip","scenario":"Your corrugate supplier just pushed delivery back a week. Without stock, Thursday's packaging run stops, and you need the director to approve a spot buy from an alternate supplier today. Your draft opens with the history of the supplier relationship.","task":"Write a 2-3 sentence message that leads with the risk and the approval you need.","tips":["Sentence one: what stops, when, and why.","Sentence two: the fix and its cost — the decision you need today.","Supplier history is background; cut or compress it."],"focus":["clarity","impact"],"placeholder":"Corrugate delivery slipped a week — Thursday's run stops unless we spot-buy today."},
    {"id":"lead-ops-mid-06","level":"mid","profession":"operator","title":"The temp headcount request","scenario":"Peak volume starts in three weeks and you need 8 temporary associates from the regional shared pool. Your draft to the regional manager opens with two paragraphs on the volume forecast before making the request.","task":"Write a request that states the number, roles, and dates in the first sentence.","tips":["Lead with the ask: 8 temps, which roles, which weeks.","One sentence of forecast justifies it; the full model can be attached.","Name the date you need the answer by — pools run out."],"focus":["clarity","precision"]},
    {"id":"lead-ops-mid-07","level":"mid","profession":"operator","title":"The near-miss notice","scenario":"Last night a forklift reversed within a foot of a picker at dock 3. You're writing the site notice, and your draft opens by quoting the traffic-management policy section before describing what happened.","task":"Write a 2-3 sentence notice that leads with what happened and the immediate change.","tips":["First sentence: the event, plainly stated.","Second: what changes now — the pedestrian lane is enforced from today.","Policy citations support the change; they aren't the headline."],"focus":["clarity","impact"],"placeholder":"Last night a forklift reversed within a foot of a picker at dock 3."},
    {"id":"lead-ops-mid-08","level":"mid","profession":"operator","title":"The schedule change announcement","scenario":"First-shift start moves from 6:00 to 5:30 beginning Monday, to catch the carrier's earlier pickup window. Your draft to supervisors opens with the story of the carrier negotiation before stating the change.","task":"Write an announcement that puts the change and the date in the first sentence.","tips":["Lead with what changes and when — that's what supervisors must relay.","One line on why is enough.","Close with what supervisors should do: confirm crew notification by Thursday."],"focus":["clarity","structure"]},
    {"id":"lead-ops-mid-09","level":"mid","profession":"operator","title":"The yes the director wants","scenario":"The site director messages: 'Will we hit today's ship target?' You're trending 1,850 cases against a 1,800 target, with one risk — a late inbound trailer carrying components for 200 of them. Your instinct is to explain the trailer situation first.","task":"Write a reply that answers the question in the first word, then names the one risk.","tips":["Answer first: yes.","The risk is a caveat, not a preamble.","Give the checkpoint — when you'll know the trailer made it."],"focus":["concision","clarity"],"placeholder":"Yes — trending 1,850 against 1,800. One risk:"},
    {"id":"lead-ops-mid-10","level":"mid","profession":"operator","title":"The maintenance window ask","scenario":"Line 1 needs a two-hour gearbox PM and the least damaging slot is Tuesday 6-8 a.m. — but production planning must move a wave to make room. Your draft to the planning lead explains the failure history before making the request.","task":"Write a message that puts the specific window and the ask in the first sentence.","tips":["Lead with the window: line 1 down Tuesday 6-8 a.m., need the wave moved.","One sentence on why the PM can't wait.","Offer the alternative slot so they can trade, not just object."],"focus":["clarity","structure"]},
    {"id":"lead-ops-mid-11","level":"mid","profession":"operator","title":"The agency recommendation","scenario":"The director asked which of two temp agencies to contract for peak. You compared them thoroughly and have a clear pick — better fill rate and an on-site coordinator — but your reply walks through the comparison for three paragraphs before landing on it.","task":"Rewrite so the recommendation comes first, with the two deciding reasons after.","tips":["State the pick in sentence one.","Give the two reasons that actually decided it, not all six criteria.","The full comparison can be an attachment."],"focus":["structure","clarity"],"placeholder":"Go with Meridian —"},
    {"id":"lead-ops-mid-12","level":"mid","profession":"operator","title":"The hold that must land first","scenario":"QA found label misprints in lot 4471. The lot must be held and two pallets already staged at dock 2 pulled before the 2 p.m. trailer. Your draft to the shift supervisors describes how QA discovered the defect before giving the instruction.","task":"Write a message that leads with the directive: what stops, what gets pulled, by when.","tips":["Instruction first: hold lot 4471, pull the two staged pallets before 2 p.m.","Who confirms completion, and to whom, in sentence two.","The discovery story can wait for the debrief."],"focus":["clarity","impact"]},
    {"id":"lead-ops-mid-13","level":"mid","profession":"operator","title":"The root-cause headline","scenario":"Friday's three-hour downtime traced to a worn bearing that the last PM missed. Your update to the director walks through the whole investigation — vibration readings, teardown, parts inspection — before naming the cause.","task":"Write a 2-3 sentence update that leads with the finding and the fix.","tips":["Sentence one: the cause, plainly.","Sentence two: what changes so it doesn't recur — the PM checklist gets the bearing check.","Investigation detail is available on request, not in the headline."],"focus":["structure","concision"]},
    {"id":"lead-ops-mid-14","level":"mid","profession":"operator","title":"The overflow ask to a sister site","scenario":"Your dock resurfacing takes four doors offline for two weeks starting the 10th, and you need the sister DC to absorb four outbound trailers a day. Your draft to their ops manager opens with the resurfacing project's background.","task":"Write a message that leads with the ask and the dates.","tips":["Lead with the request: four trailers a day, the 10th through the 24th.","One line of why — doors offline — is all the context they need.","Make it easy to answer: offer a call slot to work the details."],"focus":["clarity","concision"]},
    {"id":"lead-ops-mid-15","level":"mid","profession":"operator","title":"The variance heads-up","scenario":"Maintenance spend will finish the quarter roughly $18k over budget after two unplanned motor replacements. You'd rather your director hear it from you now than see it in the finance pack. Your draft eases in with how well the rest of the budget is tracking.","task":"Write a heads-up that leads with the number.","tips":["Lead with the overrun: about $18k over, this quarter.","The cause in one clause: two unplanned motor failures.","Say what you're doing — the spare-part proposal — so the news comes with a plan."],"focus":["precision","impact"],"placeholder":"Heads-up: maintenance will close the quarter about $18k over budget."},
    {"id":"lead-ops-mid-16","level":"mid","profession":"operator","title":"The slip you have to own","scenario":"The pick-path redesign go-live moves from June 8 to June 22 because the racking delivery slipped. You're nervous telling the director, so your draft opens with everything the project has achieved so far.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that's the decision-relevant fact.","The reason takes one clause, not a paragraph.","Say what's protected: peak readiness is unaffected."],"focus":["clarity","impact"]},
    {"id":"lead-ops-mid-17","level":"mid","profession":"operator","title":"The toolbox talk that leads","scenario":"Today's toolbox talk has one message: lock out the baler before clearing jams — a contractor was seen reaching into it yesterday. Your usual opening covers announcements, the weather, and the week's schedule first.","task":"Script the first two sentences so the one behavior leads.","tips":["Open with the behavior: lock out the baler, every jam, every time.","Then the one-sentence reason — what was seen yesterday.","Announcements can wait until the safety point has landed."],"focus":["impact","clarity"]},
    {"id":"lead-ops-mid-18","level":"mid","profession":"operator","title":"The answer customer service needs","scenario":"The account team asks where order 88412 is — the customer is chasing. It ships today and delivers Thursday; it was delayed by yesterday's line stoppage. Your draft explains the stoppage before answering the question.","task":"Write a reply that gives the ship and delivery dates in the first sentence.","tips":["Answer the question first: ships today, delivers Thursday.","Cause in one clause, only because it helps them talk to the customer.","Offer the tracking number so they don't have to ask again."],"focus":["concision","audience"]},
    {"id":"lead-ops-mid-19","level":"mid","profession":"operator","title":"The rollout announcement","scenario":"The new cycle-count procedure starts Monday: counts move to the first hour of each shift, and supervisors sign off daily. Your draft announcement opens with a history of the site's inventory-accuracy problems.","task":"Write an announcement whose first sentence states what changes and when.","tips":["Lead with the change and the date.","Then the two specifics people must act on: first-hour counts, daily sign-off.","One line of why is enough — accuracy history isn't the headline."],"focus":["clarity","structure"],"placeholder":"Starting Monday, cycle counts move to the first hour of each shift."},
    {"id":"lead-ops-mid-20","level":"mid","profession":"operator","title":"The spare-part ask","scenario":"After two drive-motor failures in four months, you want approval to stock a spare on site: $6,400 against roughly $12k of downtime per failure event. Your draft builds the failure history for two paragraphs before asking.","task":"Write a 2-3 sentence request that leads with the ask and the trade.","tips":["Sentence one: approve a $6,400 spare drive motor.","Sentence two: the math — each failure without one costs about $12k.","Two failures in four months is the evidence; one clause covers it."],"focus":["clarity","precision"]},
    {"id":"lead-ops-mid-21","level":"mid","profession":"operator","title":"The absenteeism flag","scenario":"Night-shift unplanned absence hit 9% this month against a 4% site norm, and you've started return-to-work conversations to find the pattern. You're flagging it upward, but your draft opens with a general reflection on labor-market conditions.","task":"Write a 2-3 sentence flag that leads with the number and your action.","tips":["Lead with the fact: nights at 9% versus a 4% norm.","Say what you're already doing — this is a flag, not a request for rescue.","Name when you'll report back with the pattern."],"focus":["precision","impact"]},
    {"id":"lead-ops-mid-22","level":"mid","profession":"operator","title":"The weekend handoff","scenario":"You're handing the site to the weekend duty manager. Chiller 2 tripped twice this week and may alarm again — and in your draft, the escalation contact for refrigeration is on the last line of the note.","task":"Rewrite the note's opening so the live risk and who to call lead.","tips":["First line: chiller 2 may alarm; call the refrigeration contractor's emergency line first, then you.","Put the phone number in the first line, not the footer.","Routine weekend notes follow, clearly separated."],"focus":["structure","precision"]},
    {"id":"lead-ops-mid-23","level":"mid","profession":"operator","title":"The one-line answer","scenario":"The regional VP emails a single question: 'Is the recalled lot fully isolated?' It is — all 340 cases are quarantined in the hold cage and none shipped. Your draft explains the quarantine procedure for two paragraphs first.","task":"Write a reply that answers in the first word, then gives the two facts that prove it.","tips":["First word: yes.","Then the proof: 340 cases quarantined, zero shipped.","Procedure detail is for the audit file, not this reply."],"focus":["concision","clarity"],"placeholder":"Yes — all 340 cases are quarantined; none shipped."},
    {"id":"lead-ops-mid-24","level":"mid","profession":"operator","title":"The meeting request with a point","scenario":"You need 30 minutes with your HR business partner this week about a conduct issue with one of your supervisors, before it escalates. Your draft message says 'hoping to connect when you have a moment about a few things.'","task":"Write a request that states the purpose, the urgency, and the time needed up front.","tips":["Name the topic plainly: a supervisor conduct issue that needs HR guidance.","Say why this week — waiting raises risk.","Specific asks get calendared; vague ones drift."],"focus":["clarity","precision"]},
    {"id":"lead-ops-mid-25","level":"mid","profession":"operator","title":"The pilot verdict","scenario":"Your four-week pick-path pilot cut travel time 14% with no increase in errors, and you need the director's go/no-go this week to roll it out to all shifts before July. Your draft summarizes the pilot design before giving the result.","task":"Write a 2-3 sentence message that leads with the result and the decision needed.","tips":["Sentence one: the result — travel time down 14%, errors flat.","Sentence two: the decision and the deadline that makes it urgent.","Pilot methodology goes in the attachment."],"focus":["structure","impact"],"placeholder":"The pick-path pilot worked: travel time down 14%, errors flat. I need a go/no-go this week to reach all shifts by July."}
  ],
  "start-with-the-audience": [
    {"id":"audience-ops-mid-01","level":"mid","profession":"operator","title":"Explain the OEE dip to the floor","scenario":"OEE fell from 78 to 71 this month and the site director wants the floor to understand it. Your crew doesn't know the acronym and doesn't need to — they saw the line stoppages that caused it.","task":"Write a 3-4 sentence huddle explanation with no unexplained acronyms.","tips":["Start from what they experienced: the stoppages, the jams.","Translate the metric into what it means for the site and for them.","Say what changes next — one concrete action, not a lecture."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-02","level":"mid","profession":"operator","title":"Altitude for the regional VP","scenario":"You drafted three paragraphs for the regional VP explaining the gearbox failure mode, the bearing tolerances, and the maintenance history. The VP cares about three things: output impact, cost, and whether it will happen again.","task":"Rewrite the update in 3 sentences at the altitude the VP reads at.","tips":["One sentence each: output impact, cost, recurrence risk.","Cut every mechanical detail that doesn't change a decision.","Offer the engineering detail as available, not included."],"focus":["audience","concision"]},
    {"id":"audience-ops-mid-03","level":"mid","profession":"operator","title":"The system change for pickers","scenario":"The warehouse-management system update renames two screens and adds a confirmation scan on putaway. The release notes are written for IT. Your pickers care about exactly one thing: what they'll do differently on their next task.","task":"Write a 3-4 sentence explanation of what changes in the picker's own workflow.","tips":["Describe the change as steps in their task, not system features.","Name the screens by what pickers call them, not the release-note labels.","Say what to do if the new scan fails — that's their first question."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-04","level":"mid","profession":"operator","title":"The glove rule for the night shift","scenario":"A cut-resistant glove requirement starts next week and the night shift reads it as one more rule from an office that doesn't work nights. The real reason: two hand lacerations on the case cutter this year, both on nights.","task":"Write the 3-4 sentence rationale framed around their risk, not the regulation.","tips":["Lead with what happened to people like them, on their shift.","Regulation is the floor, not the reason — talk about hands, not clauses.","Acknowledge the annoyance honestly; don't pretend gloves are comfortable."],"focus":["audience","impact"]},
    {"id":"audience-ops-mid-05","level":"mid","profession":"operator","title":"Overtime in finance's language","scenario":"Finance asks why overtime rose 22% this month. Your draft explains wave schedules, call-off cascades, and coverage rules — none of which is finance's language. They think in cost per unit and run-rate.","task":"Write a 2-3 sentence answer translated into cost terms, with the recovery plan.","tips":["Convert the hours into the metric they use: cost per unit shipped.","Split the driver in their terms: volume versus absence.","End with when the run-rate returns to plan."],"focus":["audience","precision"],"placeholder":"Overtime added about $0.09 per unit shipped this month —"},
    {"id":"audience-ops-mid-06","level":"mid","profession":"operator","title":"Downtime for the account team","scenario":"Line 3 was down for three hours and roughly 40 customer orders will ship a day late. Customer service needs to call those customers today, and they can't relay your draft — it's all conveyor sections and fault codes.","task":"Write a 3-sentence explanation the account team can understand and partly reuse with customers.","tips":["Name the symptom and the effect on orders, not the machinery.","Give them one customer-safe sentence they can say verbatim.","Tell them what's already fixed so they can reassure, not just apologize."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-07","level":"mid","profession":"operator","title":"The jargon-free first day","scenario":"You welcome every new-hire group personally. Your usual intro is full of shorthand — 'grab an RF gun, you'll start on the mezz, wave 3 drops at ten' — which meant nothing to you on your first day either.","task":"Rewrite your 3-4 sentence welcome so a first-day hire follows every word.","tips":["Replace each piece of shorthand with the plain thing it means.","Tell them the one thing that matters most today: where to be, who helps them.","Save the site vocabulary lesson for the tour."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-08","level":"mid","profession":"operator","title":"The vendor email without the in-speak","scenario":"Your draft to the packaging vendor references 'the MOS boards, the 4471 hold, and our gemba findings.' The vendor has never been inside your building and can act on none of it.","task":"Rewrite the email so an outsider can understand the problem and act on the request.","tips":["Translate every internal label into what it actually is.","Lead with what you need from them and by when.","Include only the context that helps them respond."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-09","level":"mid","profession":"operator","title":"The HR ask in HR terms","scenario":"You need HR to shorten backfill approval from three weeks to one. Your draft argues in coverage math and takt time. HR weighs different things: time-to-fill benchmarks, attrition risk, and scheduling-compliance exposure.","task":"Reframe the request in 3-4 sentences around what HR owns and measures.","tips":["Argue in their currency: attrition risk and compliance, not takt.","Show what the three-week gap costs in terms HR reports upward.","Make the ask specific: one-week approval for like-for-like backfills."],"focus":["audience","impact"]},
    {"id":"audience-ops-mid-10","level":"mid","profession":"operator","title":"One audience at a time","scenario":"Your quality-hold email tries to serve QA — disposition codes and sampling detail — and the floor team — what to stop touching — in the same message. Both audiences have to wade through the other's half.","task":"Rewrite the message for the floor team only, noting what moves to a separate QA note.","tips":["Pick the primary audience: the people who must physically stop work.","Their version: what's held, where it is, what not to touch, who to ask.","Disposition detail goes to QA in its own message."],"focus":["audience","structure"]},
    {"id":"audience-ops-mid-11","level":"mid","profession":"operator","title":"Plain words for a mixed-language crew","scenario":"You're announcing the new pallet-stacking standard to a crew where many associates speak English as a second language. Your draft uses phrases like 'ensure load integrity is maintained at all times.'","task":"Rewrite the announcement in 3-4 short sentences, one instruction each, in common words.","tips":["One instruction per sentence, no subordinate clauses.","Use the words on the floor signage — red line, top layer — not abstractions.","Pair it with the picture: say where the visual example is posted."],"focus":["audience","clarity"],"placeholder":"From today: stack no higher than the red line."},
    {"id":"audience-ops-mid-12","level":"mid","profession":"operator","title":"Telling IT the real problem","scenario":"Your draft ticket asks IT to 'fix the access points in the far aisles.' What you actually know: scanners drop connection in aisles 40-48, forcing re-scans that cost each picker about 20 picks an hour there.","task":"Rewrite the request describing the problem and its impact, not your guessed solution.","tips":["Report the symptom and where it happens — let IT diagnose the cause.","Quantify the impact so they can prioritize it honestly.","Offer what helps them: times it's worst, which device models."],"focus":["audience","precision"]},
    {"id":"audience-ops-mid-13","level":"mid","profession":"operator","title":"Three lines for the director","scenario":"The site director asked how the conveyor extension project is going. Your draft covers bearing specifications, contractor scheduling conflicts, and a bracket redesign. The director wants status, date, and risk.","task":"Write the 3-sentence version at the director's altitude.","tips":["One sentence each: status, completion date, biggest risk.","Every engineering detail must earn its place by changing a decision.","If the date moved, that's the first sentence."],"focus":["audience","concision"]},
    {"id":"audience-ops-mid-14","level":"mid","profession":"operator","title":"The peer who's never seen your building","scenario":"A peer ops manager at another site wants to copy your dock-scheduling approach. Your write-up is full of local shorthand — 'the far doors,' 'B-shift rules,' 'the 10:40 wave' — that only your site understands.","task":"Rewrite the first paragraph so someone who has never visited can follow it.","tips":["Replace local names with the general concept they stand for.","State the principle first, then your local example of it.","Test each sentence: would it survive being read at their site?"],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-15","level":"mid","profession":"operator","title":"The talk framed on their risk","scenario":"Trailer-restraint compliance at the docks has slipped, and your draft talk cites the relevant OSHA sections. What actually persuades a forklift driver is what happens when a trailer creeps while they're inside it.","task":"Rewrite the 3-4 sentence talk opening around what the driver personally risks.","tips":["Paint the physical event: trailer creeps, forklift drops the gap.","Regulations back you up; they don't do the persuading.","End with the one behavior: restraint locked and light green before entry."],"focus":["audience","impact"]},
    {"id":"audience-ops-mid-16","level":"mid","profession":"operator","title":"The rep meeting frame","scenario":"You're presenting the rotating-weekend proposal to the employee representatives. Your draft is built around coverage math and cost. Their questions will be about predictability, fairness across tenure, and how swaps work.","task":"Write the 3-4 sentence opening framed around their concerns, not your math.","tips":["Open with what matters to them: schedules known 4 weeks out, rotation applied evenly.","Bring the coverage math as backup, not the lead.","Name the concern you can't fully fix — honesty buys the rest a hearing."],"focus":["audience","impact"]},
    {"id":"audience-ops-mid-17","level":"mid","profession":"operator","title":"The dashboard without the fear","scenario":"You're introducing an hourly performance board and your supervisors are bracing the crews for surveillance. What it actually does: shows when a zone is falling behind so help arrives in the same hour, not at the shift debrief.","task":"Write a 3-4 sentence explanation framed around what the board does for the crew.","tips":["Lead with the benefit they feel: help arrives sooner, staffing gets fairer.","Say plainly what it will not be used for — and mean it.","Invite the test: judge it after two weeks of seeing it work."],"focus":["audience","impact"],"placeholder":"The hourly board is how we send help sooner —"},
    {"id":"audience-ops-mid-18","level":"mid","profession":"operator","title":"The customer on the floor","scenario":"A key customer tours the site Friday and will ask how you catch quality problems before they ship. Your internal answer is full of hold codes, CAPA logs, and sampling plans.","task":"Write a 3-4 sentence answer in the customer's terms: what it means for their orders.","tips":["Anchor on their stake: what reaches their shelves is checked, and how.","One concrete example beats three acronyms.","Keep the confidence factual — describe checks, don't promise perfection."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-19","level":"mid","profession":"operator","title":"Corporate memo, local meaning","scenario":"Corporate sent a network-wide memo about the 'inventory integrity initiative.' At your site it means exactly two things: two extra cycle counts a week and a monthly aisle audit. Your team shouldn't have to decode the memo themselves.","task":"Write the 3-sentence translation: what actually changes at this site, starting when.","tips":["Skip the initiative language; name the two concrete changes.","Say who does what and from which week.","Link the memo for the curious rather than summarizing all of it."],"focus":["audience","concision"]},
    {"id":"audience-ops-mid-20","level":"mid","profession":"operator","title":"The question they're really asking","scenario":"You're announcing an autonomous-forklift pilot in one aisle. The crew's real question won't be about the technology — it will be 'do I still have a job?' Your draft describes the robot's specifications first.","task":"Write the announcement so the first sentences answer the question they actually have.","tips":["Address employment first, honestly — say exactly what is and isn't decided.","Then the pilot facts: one aisle, ninety days, what it carries.","Don't over-promise; a hedge kept is worth more than a promise broken."],"focus":["audience","impact"]},
    {"id":"audience-ops-mid-21","level":"mid","profession":"operator","title":"The shrink answer for the CFO","scenario":"On the monthly ops call the CFO asks about inventory shrink. Your draft explains cycle-count mechanics and adjustment workflows. The CFO wants the dollar figure, the trend, and what changed.","task":"Write the 2-3 sentence answer in the CFO's terms.","tips":["Lead with the number as a percent of cost of goods and the trend.","Name the one control you added, not the whole counting process.","Stop after three sentences — invite the follow-up instead of pre-answering it."],"focus":["audience","precision"],"placeholder":"Shrink is 0.4% of COGS, down from 0.6% last quarter —"},
    {"id":"audience-ops-mid-22","level":"mid","profession":"operator","title":"The job ad that speaks to candidates","scenario":"Your warehouse-associate posting opens with two sentences of company history and values. Candidates scanning ten postings weigh three things: pay, whether the schedule is fixed, and how weekends work.","task":"Rewrite the first 3 sentences around what candidates actually weigh.","tips":["Lead with pay and the schedule pattern — the real differentiators.","State the weekend rotation plainly; surprises there drive early quits.","Company story earns one sentence at the end, not two at the top."],"focus":["audience","clarity"]},
    {"id":"audience-ops-mid-23","level":"mid","profession":"operator","title":"The contractor's five things","scenario":"A refrigeration contractor starts a two-day job on site tomorrow. Your induction draft is the full 12-page site handbook. For this job they need perhaps five rules — and they need to actually remember them.","task":"Write the five site rules this contractor actually needs, one line each.","tips":["Pick rules by what this job touches: roof access, refrigerant handling, permits, escorts.","One line per rule, imperative voice.","The handbook is reference; the five lines are the induction."],"focus":["audience","concision"]},
    {"id":"audience-ops-mid-24","level":"mid","profession":"operator","title":"The carrier's version of peak","scenario":"Your peak plan email to the trucking carrier is organized around your internal wave times and staffing plan. What the carrier needs: volumes by week, pickup windows, and which dates surge.","task":"Rewrite the email around the three things the carrier plans against.","tips":["Give volume by week in their unit: trailers, not cases.","State pickup windows as commitments they can staff to.","Flag the two surge dates in the first paragraph, not the footnote."],"focus":["audience","precision"],"placeholder":"For your planning: weeks 47-50 we'll tender 14, 18, 22, and 19 trailers —"},
    {"id":"audience-ops-mid-25","level":"mid","profession":"operator","title":"Two audiences, two messages","scenario":"You drafted one email announcing the shift-pattern change to both the floor crews and the leadership team. The crews need what changes for them; leadership needs cost and coverage effects. One message serves neither.","task":"Write the crew version in 3-4 sentences, and note in one line what moves to the leadership version.","tips":["Crew version: their new hours, start date, how to raise conflicts.","Cost and coverage math belongs in the leadership note only.","One primary audience per message — always."],"focus":["audience","structure"]}
  ],
  "structure-that-carries": [
    {"id":"structure-ops-mid-01","level":"mid","profession":"operator","title":"Three buckets for the downtime review","scenario":"Your monthly downtime review to site leadership lists 14 stoppage events in the order they happened. Leadership can't see the pattern in a chronological wall, and the meeting drifts into event-by-event debate.","task":"Reorganize the 14 events into one governing message supported by no more than three cause buckets.","tips":["Lead with the single takeaway: where the downtime concentrates.","Group the 14 events into at most three causes — mechanical, changeover, staffing.","Chronology is data; the grouping is the argument."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-02","level":"mid","profession":"operator","title":"SCQA for the staffing case","scenario":"You're asking the regional manager for a permanent headcount increase. Your draft jumps straight to the number without setting up why now. The reader has no frame for whether the request is reasonable.","task":"Restructure the request as situation, complication, question, answer in 4-5 sentences.","tips":["Situation: the stable baseline everyone agrees on.","Complication: what changed — volume up 15% on flat headcount.","Question then answer: what do we do, and your recommended number."],"focus":["structure","impact"],"placeholder":"For two years we ran this volume with 42 associates."},
    {"id":"structure-ops-mid-03","level":"mid","profession":"operator","title":"PREP for the safety question","scenario":"In the leadership huddle you'll be asked, live, whether the dock is safe to reopen after the spill. You know the answer is yes with one condition, but you tend to ramble when put on the spot.","task":"Script a 4-sentence spoken answer using point, reason, example, point.","tips":["Point: yes, with the aisle cordon staying up until noon.","Reason: the spill's contained and the floor's been tested.","Example: the two adjacent bays reopened this way last month; point restated."],"focus":["structure","concision"]},
    {"id":"structure-ops-mid-04","level":"mid","profession":"operator","title":"The messy action list","scenario":"After the process-change kickoff you send 11 follow-up actions in a jumbled list — some for maintenance, some for supervisors, some for you. Recipients scan it, don't find their items, and nothing moves.","task":"Regroup the 11 actions under owners, so each person sees only their block.","tips":["Group by owner first — that's how people read an action list.","Within each owner, order by due date.","Put the owner's name as the heading, not buried mid-line."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-05","level":"mid","profession":"operator","title":"One idea for the town hall","scenario":"Your quarterly all-hands script covers safety, output, the new WMS, a parking change, and holiday scheduling with equal weight. The crew leaves remembering none of it because nothing was the point.","task":"Pick the one governing message and structure the other four items as support or footnotes.","tips":["Decide the single thing they must remember this quarter.","Everything else either supports it or gets a one-line mention at the end.","If five things are equally important, none of them is."],"focus":["structure","impact"]},
    {"id":"structure-ops-mid-06","level":"mid","profession":"operator","title":"Pyramid for the CapEx ask","scenario":"You want $85k for a second labeling station. Your draft is a bottom-up build: throughput math, then queue analysis, then the conclusion at the very end. Leadership wants the point at the top with the support beneath.","task":"Restructure top-down: the recommendation first, then three supporting reasons.","tips":["Sentence one: fund the second labeling station, $85k.","Then exactly three pillars — throughput, overtime saved, error reduction.","Detail hangs under each pillar; the reader can stop after the top layer."],"focus":["structure","precision"],"placeholder":"Recommendation: approve a second labeling station at $85k."},
    {"id":"structure-ops-mid-07","level":"mid","profession":"operator","title":"The incident report that wanders","scenario":"Your incident write-up mixes what happened, why it happened, and what you'll do in no particular order across two paragraphs. The reader can't tell timeline from analysis from action.","task":"Restructure into three labeled parts: what happened, root cause, corrective action.","tips":["Separate the three cleanly — never blend timeline with analysis.","Keep 'what happened' factual and free of blame or cause.","Corrective action ends with owners and dates."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-08","level":"mid","profession":"operator","title":"Signposting the shift plan","scenario":"You're briefing supervisors on a complex peak-day plan with staffing, wave timing, and contingency. You dive into details with no map, and halfway through nobody knows which part you're on.","task":"Write a 2-sentence opening that signposts the three parts before you dive in.","tips":["Tell them the shape first: staffing, then waves, then the contingency.","Number the parts so they can track where you are.","A 15-second map saves 15 minutes of confusion."],"focus":["structure","clarity"],"placeholder":"Three things this morning: staffing, the wave schedule, and the plan if the trailer's late."},
    {"id":"structure-ops-mid-09","level":"mid","profession":"operator","title":"Grouping the vendor complaints","scenario":"You're escalating to the pallet supplier and your draft lists nine separate quality problems in the order you noticed them. Nine scattered gripes read as nagging; grouped, they read as a pattern.","task":"Group the nine issues into two or three themes with a governing claim.","tips":["Find the themes — dimensional, moisture, delivery — and sort under them.","Lead with the claim the themes prove: consistency has slipped.","A pattern demands action; a list invites excuses."],"focus":["structure","precision"]},
    {"id":"structure-ops-mid-10","level":"mid","profession":"operator","title":"SCQA for the shift-swap proposal","scenario":"You're proposing to move the second-shift break window. Your draft opens with the solution, leaving supervisors unsure what problem it solves. Without the setup, it sounds like change for its own sake.","task":"Reframe as situation, complication, question, answer in 4 sentences.","tips":["Situation: the current break window everyone knows.","Complication: it collides with the 3 p.m. carrier pickup.","Question and answer: what to do, and your proposed new window."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-11","level":"mid","profession":"operator","title":"The KPI pack with no spine","scenario":"Your weekly KPI pack to the regional manager is eight metrics on eight lines with no hierarchy. Everything looks equally urgent, so nothing gets attention.","task":"Restructure so one headline metric leads and the rest support or contextualize it.","tips":["Choose the metric that governs the week — usually on-time ship.","Lead with it and its trend; group the others as drivers.","A pack with a spine gets read; a flat list gets skimmed."],"focus":["structure","concision"]},
    {"id":"structure-ops-mid-12","level":"mid","profession":"operator","title":"PREP for the overtime pushback","scenario":"A supervisor challenges you in the huddle: 'Why are we the site that always runs weekend overtime?' You want to answer with structure, not defensiveness.","task":"Answer in 4 sentences using point, reason, example, point.","tips":["Point: it's volume timing, not a staffing failure — and it's temporary.","Reason: peak lands here three weeks before the network levels out.","Example: last year's same window; then restate the point and the end date."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-13","level":"mid","profession":"operator","title":"The three-part rollout note","scenario":"You're announcing a new putaway procedure and your draft mixes the reason, the steps, and the timeline in one dense block. Supervisors can't extract the steps they need to teach.","task":"Restructure into why, what changes, and when in three clear sections.","tips":["One short paragraph per part, labeled.","The 'what changes' section is numbered steps — that's what gets taught.","Timeline last, with the go-live date bolded in their minds by position."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-14","level":"mid","profession":"operator","title":"One governing idea for the QBR","scenario":"Your quarterly business review slides to regional leadership have 20 charts and no argument. Each chart is fine; together they say nothing. Leadership asks 'so what should we conclude?'","task":"Write the single governing sentence the whole review supports, plus the three charts that prove it.","tips":["State the conclusion the quarter earns — improving, at risk, or steady.","Keep only the three charts that carry that claim; the rest are appendix.","Every slide should ladder up to the one sentence."],"focus":["structure","impact"]},
    {"id":"structure-ops-mid-15","level":"mid","profession":"operator","title":"Grouping the audit findings","scenario":"The internal safety audit returned 17 findings and your draft response addresses them one by one down the list. The reader drowns; you can't tell the systemic issues from the one-offs.","task":"Group the 17 into themes and lead with which theme carries the real risk.","tips":["Cluster by root theme — housekeeping, guarding, training, documentation.","Lead with the theme that could actually hurt someone.","Rank the themes; give each a single owner."],"focus":["structure","precision"]},
    {"id":"structure-ops-mid-16","level":"mid","profession":"operator","title":"SCQA for the equipment replacement","scenario":"You want to replace the aging sortation belt before it fails in peak. Your draft is a list of symptoms with the ask buried at the end. There's no narrative pulling the reader to yes.","task":"Structure as situation, complication, question, answer in 4-5 sentences.","tips":["Situation: the belt's run reliably for eight years.","Complication: failure rate is climbing and peak is 10 weeks out.","Question and answer: replace now or risk peak — recommend replacing now."],"focus":["structure","impact"],"placeholder":"The sortation belt has run reliably for eight years."},
    {"id":"structure-ops-mid-17","level":"mid","profession":"operator","title":"The handover with a real structure","scenario":"Your shift-to-shift handover is a stream of consciousness — a bit about line 2, a note about a late trailer, back to line 2, a staffing gap. The incoming manager has to reconstruct the state themselves.","task":"Restructure the handover into fixed sections: live risks, in-progress, watch items.","tips":["Same three headings every time — the incoming manager learns where to look.","Live risks first, always; that's the 2 a.m. section.","In-progress and watch items follow, each a tight line."],"focus":["structure","concision"]},
    {"id":"structure-ops-mid-18","level":"mid","profession":"operator","title":"Pyramid for the process-change memo","scenario":"Your memo proposing a change to the returns process builds slowly through background before reaching the recommendation on page two. Busy supervisors stop reading before they get there.","task":"Flip it top-down: the change first, then the three reasons it's worth the disruption.","tips":["Open with the recommended change in one sentence.","Three reasons beneath — faster, cheaper, fewer errors.","Background becomes support under the reasons, not a preamble."],"focus":["structure","concision"]},
    {"id":"structure-ops-mid-19","level":"mid","profession":"operator","title":"PREP for the vendor negotiation","scenario":"On a call the corrugate vendor asks why you're pushing for a price hold. You want to make the case cleanly, not meander into a history of the account.","task":"Make the case in 4 sentences using point, reason, example, point.","tips":["Point: hold this year's price given our volume commitment.","Reason: we're growing tender with you, not shrinking it.","Example: the two new lines we're routing to you; restate the point."],"focus":["structure","impact"]},
    {"id":"structure-ops-mid-20","level":"mid","profession":"operator","title":"The three risks, ranked","scenario":"Heading into peak you email leadership a list of eight things that could go wrong, unranked. Everything reads as equally likely and equally bad, so leadership can't help you prioritize mitigation.","task":"Restructure to the top three risks ranked by likelihood times impact, each with a mitigation.","tips":["Cut to three — the ones worth leadership's attention.","Rank them; say why the top one is top.","Pair each with its one mitigation, not a paragraph of worry."],"focus":["structure","precision"]},
    {"id":"structure-ops-mid-21","level":"mid","profession":"operator","title":"One idea for the supervisor coaching note","scenario":"You're writing development feedback for a supervisor and cram five improvement areas into one note. They can't act on five at once, so they act on none.","task":"Restructure around the one priority area, with the rest noted as future.","tips":["Pick the single thing that would most change their results now.","Structure the note around that one theme with concrete examples.","List the others briefly as 'next, once this lands.'"],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-22","level":"mid","profession":"operator","title":"SCQA for the layout change","scenario":"You want to reconfigure the pack stations to cut walking. Your draft leads with the new layout diagram, which confuses everyone before they know what problem it solves.","task":"Frame with situation, complication, question, answer before showing any diagram.","tips":["Situation: current station layout and its walking distance.","Complication: that walking is 12% of pack time.","Question and answer: how to cut it, and the reconfiguration you propose."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-23","level":"mid","profession":"operator","title":"The debrief with three lessons","scenario":"After the failed inventory count you write a debrief that lists everything that went wrong in narrative form. Leadership wants the lessons, structured, not a retelling.","task":"Restructure into three lessons learned, each with what changes because of it.","tips":["Distill the narrative into at most three transferable lessons.","Each lesson pairs with a concrete process change.","The story is evidence for the lessons, not the deliverable."],"focus":["structure","precision"]},
    {"id":"structure-ops-mid-24","level":"mid","profession":"operator","title":"Signpost the multi-site update","scenario":"You coordinate three sites' contribution to a regional project and your status email jumps between them unpredictably. Readers lose track of which site you're describing.","task":"Restructure with a signposted section per site and a one-line overall status on top.","tips":["Lead with the one-line portfolio status: on track, or the exception.","Then a fixed block per site, same order every week.","Consistency in structure is what makes a recurring update scannable."],"focus":["structure","clarity"]},
    {"id":"structure-ops-mid-25","level":"mid","profession":"operator","title":"Pyramid for the peak readiness brief","scenario":"Your peak readiness brief to leadership is 12 workstreams listed flat. Leadership can't tell if you're ready. They need one verdict and the few things that could change it.","task":"Restructure top-down: overall readiness verdict, then the three open risks beneath.","tips":["Sentence one: the verdict — ready, or ready-except.","Group the 12 workstreams; surface only the three that aren't green.","Leadership acts on the exceptions, not the twelve."],"focus":["structure","impact"],"placeholder":"Peak readiness: green on nine workstreams, three still open."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-ops-mid-01","level":"mid","profession":"operator","title":"Halve the shift email","scenario":"Your end-of-shift summary to leadership runs six paragraphs. It opens with 'I wanted to take a moment to provide a comprehensive update regarding the events of today's shift' and never tightens from there.","task":"Cut the summary to under 80 words with no loss of fact.","tips":["Delete the throat-clearing opener entirely — start with the facts.","Kill nominalizations: 'provide an update' becomes 'update.'","If a sentence survives deletion untouched by meaning, delete it."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-02","level":"mid","profession":"operator","title":"The hedged escalation","scenario":"Your escalation reads: 'It seems like there may possibly be some risk that we might not quite hit today's target, though it's still somewhat early to say for certain.' Leadership can't tell if this is urgent.","task":"Rewrite in one direct sentence that states the risk plainly.","tips":["Strip the stacked hedges — 'seems,' 'may,' 'possibly,' 'might.'","State the probability if you have it; otherwise state the risk cleanly.","One confident sentence outweighs three tentative ones."],"focus":["concision","impact"],"placeholder":"We're likely to miss today's target by about 150 cases unless the trailer arrives by noon."},
    {"id":"concise-ops-mid-03","level":"mid","profession":"operator","title":"Redundant pairs in the safety notice","scenario":"Your safety notice is full of doubled phrasing: 'each and every,' 'safe and secure,' 'first and foremost,' 'clear and obvious.' It reads padded, and the actual instruction gets lost.","task":"Rewrite the notice cutting every redundant pair to a single word.","tips":["Pick one word from each pair — 'every,' 'secure,' 'first,' 'clear.'","Padding dilutes urgency; a safety notice can't afford it.","Read it aloud — the pairs will announce themselves."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-04","level":"mid","profession":"operator","title":"Cut the meta-commentary","scenario":"Your process update spends its first three sentences describing the update: 'In this message I will outline the changes, explain the rationale, and then cover next steps.' Supervisors want the changes, not the table of contents.","task":"Rewrite so it starts with the actual content, no preview of itself.","tips":["Delete 'in this message I will' openers — just say the thing.","For a short note, a table of contents is longer than the note.","Trust the reader to see the structure as they read it."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-05","level":"mid","profession":"operator","title":"The bloated KPI comment","scenario":"Your comment on the on-time-ship metric reads: 'Due to the fact that we experienced a number of different issues, we were not able to achieve the level of performance that we would have ideally liked to see.' It says almost nothing.","task":"Rewrite in one sentence that names the number and the cause.","tips":["'Due to the fact that' is always just 'because.'","Replace the vague 'number of issues' with the actual driver.","Give the reader the figure they came for."],"focus":["concision","precision"],"placeholder":"On-time ship hit 94% because two line stoppages cost us the afternoon waves."},
    {"id":"concise-ops-mid-06","level":"mid","profession":"operator","title":"Nominalizations in the proposal","scenario":"Your staffing proposal is buried in noun-heavy phrasing: 'the implementation of a modification to the scheduling of the second shift will result in the reduction of overtime utilization.' The verbs have all turned into nouns.","task":"Rewrite using strong verbs so the sentence moves.","tips":["Turn nouns back into verbs: 'implementation of a modification' becomes 'changing.'","Nominalizations hide who does what — put actors back in.","Shorter and clearer are the same edit here."],"focus":["concision","clarity"],"placeholder":"Moving second shift's start to 5:30 would cut overtime."},
    {"id":"concise-ops-mid-07","level":"mid","profession":"operator","title":"The over-explained instruction","scenario":"Your work instruction for the new scan step spends a paragraph justifying why the step exists before telling associates what to do. On the floor, they need the action first and short.","task":"Rewrite as the instruction in two lines, with justification cut or moved to one clause.","tips":["Lead with the action: scan the tote before putaway.","One clause of why, if any — associates act, they don't need a lecture.","Every extra sentence is one more thing to skim past."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-08","level":"mid","profession":"operator","title":"Trim the vendor follow-up","scenario":"Your follow-up to the maintenance vendor restates the entire history of the ticket before asking the one question: when will the part arrive? Three paragraphs of recap bury a one-line ask.","task":"Rewrite as the question first, with only the context the vendor needs to answer.","tips":["Ask the question in sentence one — that's why you're writing.","The vendor knows the ticket; don't recap their own job to them.","Two lines of context maximum, only if it unblocks the answer."],"focus":["concision","audience"]},
    {"id":"concise-ops-mid-09","level":"mid","profession":"operator","title":"The filler-laden huddle open","scenario":"Your morning huddle opener is: 'Alright everyone, so, um, I just kind of wanted to sort of quickly touch base on a couple of things that are basically going on today.' The crew tunes out before the point.","task":"Rewrite the opener as one crisp sentence naming today's one priority.","tips":["Cut every filler: 'so,' 'kind of,' 'sort of,' 'basically.'","Name the priority in the first breath — you have seconds.","The crew mirrors your energy; vague open, vague shift."],"focus":["concision","impact"],"placeholder":"One priority today: clear the 800-case backlog before the noon wave."},
    {"id":"concise-ops-mid-10","level":"mid","profession":"operator","title":"The 200-word answer to a yes/no","scenario":"Leadership asked 'are we staffed for Saturday?' and your reply is a 200-word tour of the roster, the call-offs, and the temp pool. The answer — yes — is somewhere in there.","task":"Rewrite as the yes/no first, then at most one sentence of the load-bearing caveat.","tips":["Answer the actual question in the first word.","Keep only the one caveat that could change the answer.","Offer the roster detail on request rather than including it."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-11","level":"mid","profession":"operator","title":"Cut the qualifier stack","scenario":"Your recommendation reads: 'I would tentatively suggest that we might want to consider potentially looking into the option of adding a spare motor.' Five qualifiers smother one recommendation.","task":"Rewrite as one clean recommendation with no more than one qualifier.","tips":["Delete the qualifier chain — 'tentatively,' 'might,' 'consider,' 'potentially.'","Own the recommendation; hedging reads as not having decided.","One honest 'I recommend' beats five soft maybes."],"focus":["concision","impact"],"placeholder":"I recommend we stock a spare drive motor on site."},
    {"id":"concise-ops-mid-12","level":"mid","profession":"operator","title":"The dense incident paragraph","scenario":"Your incident note is a single 90-word sentence connecting the jam, the response, the delay, and the fix with 'and then' four times. The reader loses the thread by the third clause.","task":"Break it into three short sentences and cut what doesn't carry weight.","tips":["Split at every 'and then' — each is a new sentence.","Cut the connective padding once the sentences stand alone.","Short sentences are how you write for a tired reader."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-13","level":"mid","profession":"operator","title":"The over-softened correction","scenario":"You need to tell a supervisor a count was wrong, but your message wraps it in so much cushioning — 'no worries at all, totally understand, just a tiny thing, whenever you get a chance' — that the actual issue nearly disappears.","task":"Rewrite so the correction is clear and respectful in two sentences, cushioning cut.","tips":["Kindness is clarity here, not padding — state the issue plainly.","One respectful frame, not four layers of apology.","Over-softening can read as not meaning it."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-14","level":"mid","profession":"operator","title":"Trim the peak plan preamble","scenario":"Your peak staffing plan opens with two paragraphs on the importance of peak season and the history of past peaks before any actual plan. Supervisors need the plan, not the sermon.","task":"Cut the preamble entirely and start at the first line of the plan.","tips":["Everyone knows peak matters; don't spend words proving it.","Start at the first actionable line — dates, numbers, assignments.","If the preamble were deleted, would anyone miss it? No."],"focus":["concision","structure"]},
    {"id":"concise-ops-mid-15","level":"mid","profession":"operator","title":"The passive-voice report","scenario":"Your downtime report is all passive: 'it was determined that the line was affected by an issue that had been caused by a component that was found to have failed.' Nobody does anything; it just happens.","task":"Rewrite in active voice, cutting the words the passive smuggled in.","tips":["Name the actor: maintenance found the bearing had failed.","Passive voice is longer and vaguer — active fixes both.","Ask 'who did what' and write that."],"focus":["concision","clarity"],"placeholder":"A failed bearing stopped line 2; maintenance replaced it in 40 minutes."},
    {"id":"concise-ops-mid-16","level":"mid","profession":"operator","title":"The email that repeats itself","scenario":"Your rollout email makes the same point in the intro, the body, and the closing — 'counts move to the first hour' appears three times in three phrasings. The reader gets it the first time.","task":"Rewrite so each fact appears exactly once, cutting the redundancy.","tips":["State each point once, in its strongest position.","A closing that restates the intro is dead weight.","Trust the reader's memory across four sentences."],"focus":["concision","structure"]},
    {"id":"concise-ops-mid-17","level":"mid","profession":"operator","title":"Cut 'in order to' and friends","scenario":"Your maintenance-window request is thick with wordy connectors: 'in order to,' 'for the purpose of,' 'with regard to,' 'in the event that.' Each is two or three words doing one word's job.","task":"Rewrite replacing each padded connector with its one-word equivalent.","tips":["'In order to' is 'to'; 'in the event that' is 'if.'","'With regard to' is usually just 'about,' or deletable.","These add length and formality, never meaning."],"focus":["concision","clarity"]},
    {"id":"concise-ops-mid-18","level":"mid","profession":"operator","title":"The status update that lists everything","scenario":"Your project status to leadership lists all 18 tasks with their status, including the 15 that are simply on track. The three that matter — the exceptions — are lost in the green.","task":"Rewrite reporting only the exceptions plus a one-line 'all else on track.'","tips":["Leadership reads status for exceptions, not confirmations.","One line: 'the other 15 tasks are on track.'","Then detail only the three that need attention."],"focus":["concision","structure"],"placeholder":"Three items need attention; the other 15 are on track."},
    {"id":"concise-ops-mid-19","level":"mid","profession":"operator","title":"The over-worded thank-you","scenario":"You're recognizing the crew for a strong week, but your message is so long and effusive — five sentences of superlatives — that the recognition feels performative rather than sincere.","task":"Rewrite as two sincere sentences: the specific thing they did and its impact.","tips":["Name the specific achievement, not generic 'great work.'","One concrete result lands harder than five adjectives.","Brevity reads as sincerity; length reads as a script."],"focus":["concision","impact"]},
    {"id":"concise-ops-mid-20","level":"mid","profession":"operator","title":"Trim the escalation chain-of-thought","scenario":"Your escalation walks leadership through your entire reasoning — what you checked, what you ruled out, what you then checked — before reaching the point. They want the conclusion and can ask for the working.","task":"Rewrite leading with the conclusion, cutting the investigative narration.","tips":["Lead with what you concluded, not how you got there.","The diagnostic journey is yours; the reader needs the destination.","Offer the reasoning if asked, don't front-load it."],"focus":["concision","structure"]},
    {"id":"concise-ops-mid-21","level":"mid","profession":"operator","title":"The wordy scheduling note","scenario":"Your note about the schedule change says 'we will be making a change such that the start time will be moved to an earlier point in the morning, specifically to 5:30.' Fourteen words to say '5:30.'","task":"Rewrite in one short sentence stating the new time and start date.","tips":["Say the number: start moves to 5:30, Monday.","Cut the wind-up 'we will be making a change such that.'","Concrete and short beats formal and padded."],"focus":["concision","precision"],"placeholder":"Starting Monday, first shift begins at 5:30."},
    {"id":"concise-ops-mid-22","level":"mid","profession":"operator","title":"The overqualified apology","scenario":"After a shipping error you write four sentences of apology and self-flagellation before the one thing the customer team needs: what you're doing to fix it. The remorse crowds out the recovery.","task":"Rewrite as a one-line acknowledgment and the fix, apology trimmed to a phrase.","tips":["One clean acknowledgment — you don't need four.","Move fast to the fix; that's what reassures.","Excessive apology shifts focus to your feelings, not their problem."],"focus":["concision","audience"]},
    {"id":"concise-ops-mid-23","level":"mid","profession":"operator","title":"Cut the throat-clearing meeting invite","scenario":"Your meeting request opens with 'I hope this finds you well, and I appreciate your time in advance, and I wanted to reach out because I was hoping we could possibly find some time to discuss.' The ask hasn't started yet.","task":"Rewrite as the purpose, the time needed, and a proposed slot in two sentences.","tips":["Skip the pleasantry stack — get to the ask.","State topic, duration, and a proposed time.","A crisp invite gets accepted; a rambling one gets deferred."],"focus":["concision","clarity"],"placeholder":"Can we take 20 minutes tomorrow on the peak staffing plan?"},
    {"id":"concise-ops-mid-24","level":"mid","profession":"operator","title":"The bloated root-cause summary","scenario":"Your root-cause summary for the QA hold restates the entire timeline, quotes three policies, and describes the sampling method — when the reader needs the cause and the fix in a few lines.","task":"Rewrite to the cause and corrective action in three sentences, detail dropped.","tips":["Cause in one sentence, fix in one, owner in one.","Policy quotes and sampling method go in the attachment.","The summary is the headline, not the full file."],"focus":["concision","precision"]},
    {"id":"concise-ops-mid-25","level":"mid","profession":"operator","title":"Halve the whole weekly report","scenario":"Your weekly report to the regional manager runs a full page. Reading it back, half is filler — pleasantries, restated context, hedges, and things that are always true. The regional manager reads twenty of these.","task":"Cut the report in half, keeping every fact and losing every word that isn't one.","tips":["Delete anything that's true every week — it carries no information.","Cut hedges and connectors ruthlessly on a second pass.","If halving loses no fact, the first half was padding."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-ops-mid-01","level":"mid","profession":"operator","title":"Numbers for 'a lot of downtime'","scenario":"Your update says line 2 'had a lot of downtime lately and it's been affecting output pretty significantly.' Leadership can't act on 'a lot' — they need hours and cases.","task":"Rewrite with the actual downtime hours, the trend, and the output impact in numbers.","tips":["Replace 'a lot' with the hours: 6.5 hours across the week.","'Significantly' becomes the case count it cost.","Give the comparison — versus last week or the target."],"focus":["precision","clarity"],"placeholder":"Line 2 lost 6.5 hours this week, up from 2 last week — about 900 cases short."},
    {"id":"precision-ops-mid-02","level":"mid","profession":"operator","title":"So what for the OEE number","scenario":"Your report states 'OEE was 71% this month' and stops. Leadership sees the number but not the meaning. The insight — that a single changeover problem drives it — is missing.","task":"Add the So What: the one insight the 71% points to, and the Now What.","tips":["What: OEE at 71%. So what: changeovers eat 60% of the loss.","Now what: the single action that would move it most.","A number without an insight is just a number."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-03","level":"mid","profession":"operator","title":"Date the vague timeline","scenario":"You tell leadership the racking install will be done 'soon, probably in a few weeks, once the contractor sorts out scheduling.' They're planning peak around this and need a date.","task":"Rewrite committing to a specific date or a dated decision point.","tips":["Replace 'a few weeks' with a real date — or the date you'll have one.","'Once the contractor sorts it out' is a milestone; name when.","Vague timelines can't be planned around; dates can."],"focus":["precision","clarity"],"placeholder":"Racking install completes June 22; I'll confirm the contractor's slot by Thursday."},
    {"id":"precision-ops-mid-04","level":"mid","profession":"operator","title":"Pass the skeptic test on shrink","scenario":"You claim 'shrink is improving' to leadership. A skeptic asks: improving from what, to what, over what period, and how do you know it's real and not noise? Your draft answers none of these.","task":"Rewrite the claim so it survives a skeptical reading with numbers and baseline.","tips":["State the baseline, the current figure, and the window.","Say why it's a trend, not noise — how many periods.","Pre-empt the skeptic by including the evidence they'd demand."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-05","level":"mid","profession":"operator","title":"Quantify the staffing gap","scenario":"Your headcount request says the site is 'stretched thin and struggling to keep up with the volume increase.' The regional manager needs the gap in numbers to approve anything.","task":"Rewrite with the volume change, the current staffing, and the specific gap.","tips":["'Volume increase' becomes a percentage or unit figure.","'Stretched thin' becomes the FTE gap: we're short 4 associates on nights.","Tie the gap to a consequence they measure — overtime or missed waves."],"focus":["precision","impact"],"placeholder":"Volume is up 15% on flat headcount; nights runs 4 associates short, driving the overtime."},
    {"id":"precision-ops-mid-06","level":"mid","profession":"operator","title":"The data-dump slide","scenario":"Your review slide has a table of 40 numbers and no takeaway. Leadership stares at it waiting for you to tell them what it means. The one insight is buried in the grid.","task":"Write the single insight sentence the table supports, so the data serves a point.","tips":["Find the one thing the 40 numbers actually say.","Lead the slide with that sentence; the table becomes evidence.","If you can't name the insight, the data isn't ready to show."],"focus":["precision","structure"]},
    {"id":"precision-ops-mid-07","level":"mid","profession":"operator","title":"Replace 'pretty good' fill rate","scenario":"Asked how the temp agency is performing, you say 'pretty good, they've been reliable mostly.' The director needs the fill rate and the no-show rate to decide on the peak contract.","task":"Rewrite with the fill rate, no-show rate, and comparison to the other agency.","tips":["'Pretty good' becomes 92% fill, 4% no-show.","'Reliable mostly' becomes the actual exceptions, counted.","A number lets the director decide; an adjective doesn't."],"focus":["precision","clarity"]},
    {"id":"precision-ops-mid-08","level":"mid","profession":"operator","title":"The What-So What-Now What on overtime","scenario":"Your overtime update gives only the What: 'overtime was up this month.' Missing is what it signals and what you'll do. Leadership is left to interpret and worry.","task":"Rewrite as What, So What, Now What in three tight sentences.","tips":["What: overtime up 22%. So what: driven by nights absence, not volume.","Now what: the return-to-work plan and when it bites.","The three-part frame turns a number into a story with a resolution."],"focus":["precision","impact"],"placeholder":"Overtime rose 22%. It's absence on nights, not volume."},
    {"id":"precision-ops-mid-09","level":"mid","profession":"operator","title":"Precise the safety claim","scenario":"Your safety update says incidents are 'way down and the new procedures seem to be working really well.' The regional safety lead wants the recordable count, the rate, and the period, not enthusiasm.","task":"Rewrite with the incident count, the rate per hours worked, and the timeframe.","tips":["'Way down' becomes two recordables this quarter versus five last.","Give the rate, not just the count — normalize for hours worked.","'Seem to be working' becomes the measured before-and-after."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-10","level":"mid","profession":"operator","title":"The vague vendor complaint","scenario":"Your escalation to the pallet supplier says quality has been 'inconsistent and problematic recently.' Without specifics, they'll ask for examples and the loop drags on.","task":"Rewrite with the defect rate, the specific defects, and the dates.","tips":["'Inconsistent' becomes the reject percentage across which shipments.","Name the defects — moisture, broken stringers — with counts.","Dated, counted claims get action; vague ones get pushback."],"focus":["precision","clarity"],"placeholder":"Across the last three deliveries, 8% of pallets failed on moisture or broken stringers."},
    {"id":"precision-ops-mid-11","level":"mid","profession":"operator","title":"Cost the downtime concretely","scenario":"You want a spare part approved and argue that failures cause 'a lot of lost production and it's expensive.' Finance needs the dollar figure per failure to weigh it against the part cost.","task":"Rewrite with the cost per failure event, broken into its components.","tips":["Convert 'expensive' into dollars: labor idle plus missed shipment penalty.","Show the per-event cost against the one-time part cost.","A trade-off in numbers makes the decision for them."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-12","level":"mid","profession":"operator","title":"The 'improving' with no baseline","scenario":"You tell the director on-time performance is 'trending in the right direction.' Without the starting point and the current number, the director can't tell if it's a real recovery or wishful reading.","task":"Rewrite with the baseline, the current figure, and how many weeks of trend.","tips":["Name where it started and where it is now.","Say how many consecutive weeks — one week isn't a trend.","Direction words need numbers behind them to be trusted."],"focus":["precision","clarity"],"placeholder":"On-time ship recovered from 91% three weeks ago to 98% this week — three weeks of gains."},
    {"id":"precision-ops-mid-13","level":"mid","profession":"operator","title":"Quantify the pilot result","scenario":"Reporting the pick-path pilot, you say it 'made a noticeable difference and people seemed to like it.' The director needs the measured travel-time change and the error impact to greenlight a rollout.","task":"Rewrite with the travel-time reduction, the error change, and the sample.","tips":["'Noticeable difference' becomes 14% less travel time.","Report errors too — flat or better, with the count.","Name the sample: over four weeks, across two shifts."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-14","level":"mid","profession":"operator","title":"The skeptic on the CapEx","scenario":"Your $85k labeling-station request claims it 'will pay for itself quickly.' A skeptical finance reviewer asks: through what savings, over what period, and what if volume drops? Your draft doesn't say.","task":"Rewrite with the payback period, the savings source, and the volume assumption.","tips":["State the payback in months, tied to a named saving.","Show the volume you're assuming — and that it holds even lower.","Anticipate the downside question and answer it in the ask."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-15","level":"mid","profession":"operator","title":"Precise the absence flag","scenario":"You flag that night-shift absence is 'high and getting worse.' The HR partner needs the rate, the norm, and the trend to know whether this is a real spike or normal variation.","task":"Rewrite with the current rate, the site norm, and the direction over recent months.","tips":["'High' means nothing without the norm — give both.","Show the last three months so 'getting worse' has evidence.","Precision here decides whether HR treats it as urgent."],"focus":["precision","clarity"],"placeholder":"Night absence is 9% against a 4% norm, up from 6% two months ago."},
    {"id":"precision-ops-mid-16","level":"mid","profession":"operator","title":"One insight from the shrink data","scenario":"Your shrink report lists losses by category, by aisle, and by week — a full page of numbers. The CFO's only question will be: where's the money going, and is it one problem or many?","task":"Write the one insight the data reveals, with the number that proves it.","tips":["Find the concentration — is 70% of shrink in one category?","Lead with that insight; the tables support it.","One clear insight beats a comprehensive but silent report."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-17","level":"mid","profession":"operator","title":"Date the corrective action","scenario":"Your incident response promises to 'update the PM checklist and retrain the team soon.' The auditor needs owners and dates, not intentions, to close the finding.","task":"Rewrite each action with a named owner and a specific completion date.","tips":["'Update the checklist' gets an owner and a date.","'Retrain soon' becomes retraining complete by a named day.","Auditors close dated commitments, not good intentions."],"focus":["precision","structure"]},
    {"id":"precision-ops-mid-18","level":"mid","profession":"operator","title":"Quantify the capacity claim","scenario":"Asked if the site can absorb the sister DC's overflow, you say 'we should have some room, things are fairly manageable right now.' The regional manager needs to know how many trailers a day, reliably.","task":"Rewrite with the specific spare capacity in trailers per day and the constraint.","tips":["'Some room' becomes a number: 4 trailers a day.","Name what limits it — dock doors or labor.","Commit to a figure they can plan the overflow against."],"focus":["precision","clarity"],"placeholder":"We can take 4 extra outbound trailers a day, limited by dock labor after 2 p.m."},
    {"id":"precision-ops-mid-19","level":"mid","profession":"operator","title":"The evidence behind the recommendation","scenario":"You recommend switching temp agencies but your case rests on 'they just seem better organized.' The director will want the fill rate, the cost, and the coordinator difference in numbers before switching.","task":"Rewrite the recommendation with the two or three quantified reasons that decided it.","tips":["Turn the impression into the metrics behind it.","Two hard numbers beat a paragraph of impressions.","Lead with the recommendation, then the evidence that survives scrutiny."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-20","level":"mid","profession":"operator","title":"Precise the variance explanation","scenario":"Your budget note says maintenance is 'over because of some unexpected repairs.' Finance needs the dollar amount, the specific repairs, and whether it's one-time or ongoing.","task":"Rewrite with the overrun amount, the specific drivers, and the recurrence.","tips":["'Some unexpected repairs' becomes two named motor failures with costs.","State whether it recurs — that's finance's real question.","The dollar figure and the one-time flag are the whole answer."],"focus":["precision","clarity"],"placeholder":"Maintenance is $18k over on two one-time motor replacements — not a run-rate change."},
    {"id":"precision-ops-mid-21","level":"mid","profession":"operator","title":"The So What on the fill rate","scenario":"Your temp update reports 'fill rate was 88% this week' and stops. Leadership doesn't know if that's fine or a problem, or what it means for coverage.","task":"Add the So What: what 88% meant for coverage, and the Now What.","tips":["What: 88% fill. So what: two waves ran short-handed.","Now what: the standing order you've placed to close the gap.","The number needs its consequence and your response attached."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-22","level":"mid","profession":"operator","title":"Skeptic-proof the readiness claim","scenario":"You tell leadership the site is 'ready for peak.' A skeptic asks: ready on what evidence — have you tested the surge volume, and what's your one weak point? Your draft asserts readiness without proof.","task":"Rewrite so the readiness claim carries its evidence and names the one open risk.","tips":["Back 'ready' with the load test you ran and its result.","Name the single weak point honestly — hiding it destroys trust.","A claim that names its own risk is more credible, not less."],"focus":["precision","impact"]},
    {"id":"precision-ops-mid-23","level":"mid","profession":"operator","title":"Quantify the quality improvement","scenario":"You report the new inspection step 'is catching more problems and quality feels better.' The customer team wants the catch rate and the escaped-defect trend to reassure the account.","task":"Rewrite with the defects caught, the escape rate, and the before-and-after.","tips":["'Catching more' becomes the count caught before shipment.","'Quality feels better' becomes the customer-facing defect rate.","Give the before number so the improvement is measurable."],"focus":["precision","clarity"]},
    {"id":"precision-ops-mid-24","level":"mid","profession":"operator","title":"The dated maintenance ask","scenario":"You request a maintenance window saying the PM should happen 'in the near future before something breaks.' Planning needs the specific window and the risk-by date to make room in the schedule.","task":"Rewrite with the exact window requested and the date beyond which risk climbs.","tips":["Name the window: Tuesday 6-8 a.m.","State the by-when: risk of failure rises sharply after next week.","Precise timing lets planning trade waves; vagueness gets deferred."],"focus":["precision","clarity"],"placeholder":"Line 1 needs a 2-hour PM Tuesday 6-8 a.m.; failure risk climbs past next Friday."},
    {"id":"precision-ops-mid-25","level":"mid","profession":"operator","title":"Turn the dashboard into an insight","scenario":"Your new hourly board shows six zones' throughput in real time, and your end-of-day note just says 'the board is up and running and looks useful.' Leadership wants what it revealed, with a number.","task":"Write the one data-driven insight the first day of the board produced.","tips":["Find the pattern the board exposed — one zone lagging by a set margin.","State it with the number, then the action it prompted.","The tool's value is the insight it surfaced, not that it's live."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-ops-mid-01","level":"mid","profession":"operator","title":"Own the agency pick","scenario":"The director asked which temp agency to use for peak. Your draft lays out both options neutrally — 'Meridian has a better fill rate but costs more; Apex is cheaper but less reliable' — and leaves the choice to them. They asked you because you're closer to it.","task":"Rewrite to lead with your recommendation and own it, options as support.","tips":["State your pick first — you have a view, so give it.","A neutral menu pushes your job back to them.","Present the trade-off, then say which side you'd land on and why."],"focus":["impact","structure"],"placeholder":"I'd go with Meridian — the fill rate matters more than the cost gap in peak."},
    {"id":"presence-ops-mid-02","level":"mid","profession":"operator","title":"Separate fact from judgment on the delay","scenario":"Your update to leadership blends what happened with your read of it: 'the trailer was late, which is honestly unacceptable and shows the carrier doesn't take us seriously.' Fact and opinion are tangled, and the opinion undercuts your credibility.","task":"Rewrite separating the facts from your judgment, clearly labeled.","tips":["State the facts first, cleanly: the trailer arrived 90 minutes late.","Then your judgment, marked as such: 'my read is this is a pattern.'","Blending the two lets a reader dismiss the fact with the opinion."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-03","level":"mid","profession":"operator","title":"Signpost the peak brief","scenario":"You're briefing regional leadership on peak readiness and plan to launch straight into details. A leader with presence tells the room the shape first: how many parts, what they are, where you'll land.","task":"Write the 2-3 sentence opening that frames the brief and states your bottom line up front.","tips":["Signal the structure: three areas — staffing, equipment, and the one risk.","Give the bottom line now: ready, with one thing to watch.","Confidence is telling them where you're going before you go."],"focus":["structure","impact"]},
    {"id":"presence-ops-mid-04","level":"mid","profession":"operator","title":"The recommendation you're avoiding","scenario":"You believe the site should delay the layout change until after peak, but your note to the director hedges — 'there are arguments both ways, it's a tricky call.' You're dodging the recommendation they need.","task":"Rewrite to state your recommendation plainly with the one reason that decides it.","tips":["Make the call: delay the change until January.","'Arguments both ways' is true of everything — say where you land.","One decisive reason carries more weight than a balanced non-answer."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-05","level":"mid","profession":"operator","title":"Presence in the incident briefing","scenario":"You're briefing the site director live after a dock incident. You're rattled and it shows — you jump around, over-apologize, and bury the key facts. The director needs steadiness and a clear picture.","task":"Script a calm 4-sentence briefing: what happened, current state, next step, and your recommendation.","tips":["Lead with the facts in a steady, ordered way — panic is contagious.","State the current state plainly: contained, nobody hurt.","End owning the next step, not asking what to do."],"focus":["impact","structure"]},
    {"id":"presence-ops-mid-06","level":"mid","profession":"operator","title":"Stop hiding behind the team","scenario":"Presenting the missed target, your draft says 'the team felt we should probably have staffed more.' You made the call; owning it as 'we underestimated' reads stronger than attributing it to a vague 'the team.'","task":"Rewrite owning the decision and the recommendation in the first person.","tips":["Say 'I' or 'we' where you mean yourself — don't hide behind 'the team felt.'","Owning the miss builds more trust than deflecting it.","Then state what you'll do differently, decisively."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-07","level":"mid","profession":"operator","title":"The clean recommendation to the VP","scenario":"The regional VP asks whether to keep the site's Saturday shift running into the slow season. You've analyzed it and lean toward stopping it, but your draft presents four scenarios without a pick.","task":"Rewrite leading with your recommendation, then the two scenarios that matter.","tips":["Recommend: end Saturdays after the 15th.","Two scenarios, not four — the ones that actually differ.","The VP wants your judgment, not a spreadsheet to interpret."],"focus":["impact","structure"],"placeholder":"I recommend ending Saturday shifts after the 15th."},
    {"id":"presence-ops-mid-08","level":"mid","profession":"operator","title":"Fact and judgment on the vendor","scenario":"In your vendor review you write 'their delivery has been terrible and they clearly don't prioritize us.' The judgment ('clearly don't prioritize us') is presented as fact and isn't provable.","task":"Rewrite stating the measured facts, then your interpretation as an interpretation.","tips":["Fact: three of the last five deliveries were late.","Judgment: 'my read is we're not a priority account for them.'","Keep the provable and the inferred visibly separate."],"focus":["impact","precision"]},
    {"id":"presence-ops-mid-09","level":"mid","profession":"operator","title":"Presence when you disagree with corporate","scenario":"Corporate wants a network procedure applied at your site that you think will slow you down. Your draft either caves silently or complains. Presence is disagreeing respectfully with a clear alternative.","task":"Write a 3-4 sentence response that states your concern, the evidence, and your alternative.","tips":["Acknowledge the goal you share before the disagreement.","State the concern with evidence, not just resistance.","Offer a concrete alternative — presence proposes, it doesn't just object."],"focus":["impact","structure"]},
    {"id":"presence-ops-mid-10","level":"mid","profession":"operator","title":"The confident staffing call","scenario":"You're recommending a permanent headcount increase to the regional manager. Your draft is apologetic — 'I know budget is tight and I hate to ask, but maybe we could possibly add someone.' The apology undercuts the case.","task":"Rewrite as a confident, evidence-backed recommendation without the apology.","tips":["Drop the apology — a well-founded ask needs no sorry.","State the recommendation and the number plainly.","Let the evidence carry it; confidence is earned by the data, not the tone."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-11","level":"mid","profession":"operator","title":"Signpost the QBR opening","scenario":"You're opening the quarterly business review for regional leadership. Your instinct is to start with slide one and work through. Presence sets the frame: the verdict, the three things that got you there, and where you need their help.","task":"Write the 3-sentence QBR opening that frames the whole review.","tips":["Open with the quarter's verdict in one sentence.","Preview the three drivers you'll cover.","Name upfront the one decision you need from them today."],"focus":["structure","impact"]},
    {"id":"presence-ops-mid-12","level":"mid","profession":"operator","title":"Own the trade-off","scenario":"Leadership asks whether to prioritize the big customer's rush order or protect the standard SLA for everyone else. You have a view but your draft describes the dilemma without resolving it.","task":"Rewrite stating which you'd choose and the principle behind the choice.","tips":["Make the call and name it as a call, not a fact.","Give the principle: 'protect the many over the one, this once.'","A resolved trade-off shows judgment; a described one shows only awareness."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-13","level":"mid","profession":"operator","title":"The steady 'here's where we are'","scenario":"Mid-crisis, the director messages asking for a status. Things are bad but stabilizing. A rattled reply spreads alarm; a composed one — facts, current state, plan — settles the room.","task":"Write a 3-sentence status that's honest about the problem but conveys control.","tips":["Be honest about the severity — false calm reads as denial.","State what's stable now, not just what broke.","End with the plan and the next checkpoint; that's what conveys control."],"focus":["impact","structure"],"placeholder":"Line 2 is still down, but the situation is contained and the fix is underway."},
    {"id":"presence-ops-mid-14","level":"mid","profession":"operator","title":"Recommendation over restatement","scenario":"Asked to weigh in on the racking-delay problem, your draft restates the situation everyone already knows and stops. You were asked because they want your judgment on what to do, not a summary.","task":"Rewrite skipping the restatement, leading with what you'd do.","tips":["They know the situation — don't spend words re-describing it.","Open with your recommended action.","A restatement is what a note-taker produces; a recommendation is what a leader produces."],"focus":["impact","concision"]},
    {"id":"presence-ops-mid-15","level":"mid","profession":"operator","title":"Present the budget cut with a stance","scenario":"You're told to cut the maintenance budget 10% and asked how. Your draft lists everything that could be cut without a recommendation, effectively handing the hard choice back up.","task":"Rewrite recommending where you'd cut and flagging the one thing you'd protect.","tips":["Recommend the specific cuts, not a menu of options.","Name what you'd protect and why — that shows judgment.","Owning the hard choices is the job at this level."],"focus":["impact","structure"]},
    {"id":"presence-ops-mid-16","level":"mid","profession":"operator","title":"The fact-judgment split in the review","scenario":"Your supervisor performance review mixes observation and opinion freely: 'she's not really a leader and the crew doesn't respect her.' Unseparated, it reads as a verdict, not evidence, and won't hold up.","task":"Rewrite separating observed behavior from your assessment.","tips":["State observed facts: turnover in her area, missed sign-offs, dated.","Then your assessment, framed as your read of the pattern.","A review built on separated facts is defensible; one built on opinion isn't."],"focus":["impact","precision"]},
    {"id":"presence-ops-mid-17","level":"mid","profession":"operator","title":"Presence in the cross-site standoff","scenario":"Two sites are blaming each other for a coordination failure and you're chairing the call. Your draft either takes a side reflexively or stays vague. Presence names the shared problem and directs the fix.","task":"Write a 3-4 sentence intervention that reframes from blame to the shared fix.","tips":["Name the shared goal to reset the room from blame.","State the facts neutrally, without assigning fault first.","Direct the next step — presence moves the group forward."],"focus":["impact","structure"]},
    {"id":"presence-ops-mid-18","level":"mid","profession":"operator","title":"Own the pilot verdict","scenario":"Your pick-path pilot succeeded and the director wants your call on rolling it out. Your draft presents the results and asks 'what do you think?' You ran it; they want your recommendation, not your deference.","task":"Rewrite giving your clear go recommendation with the evidence behind it.","tips":["Recommend the rollout — you have the data, so commit.","Lead with the recommendation, then the result that backs it.","'What do you think' hands back a decision they delegated to you."],"focus":["impact","clarity"],"placeholder":"I recommend we roll the pick-path change to all shifts."},
    {"id":"presence-ops-mid-19","level":"mid","profession":"operator","title":"The composed 'no' to the sister site","scenario":"A sister site asks you to take on overflow you genuinely can't absorb without hurting your own SLA. Your draft either over-apologizes or waffles. Presence is a clear, respectful no with the reason.","task":"Write a 2-3 sentence response that declines cleanly and offers what you can do.","tips":["State the no plainly and early — don't bury it in apology.","Give the honest reason: it would breach your own commitments.","Offer the partial help you can give, if any — presence stays constructive."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-20","level":"mid","profession":"operator","title":"Signpost then recommend to the board deck","scenario":"You're contributing an operations page to the regional board deck. Your draft is dense narrative. Board readers need the headline, the structure, and your recommendation, scannable in ten seconds.","task":"Write the page's top: headline verdict, three points, and your recommendation.","tips":["One headline sentence a board member reads in three seconds.","Three supporting points, each a phrase.","End with the recommendation or ask — the reason the page exists."],"focus":["structure","impact"]},
    {"id":"presence-ops-mid-21","level":"mid","profession":"operator","title":"Present the safety incident to the regional lead","scenario":"You're reporting a recordable injury to the regional safety lead. Your draft is defensive, pre-litigating why it wasn't the site's fault. Presence reports it straight, owns the corrective action, and doesn't deflect.","task":"Write a 3-4 sentence report: what happened, the corrective action you own, no deflection.","tips":["Report the facts without defensiveness — deflection reads as evasion.","Own the corrective action; that's what presence looks like after a failure.","Separate the factual account from any cause analysis clearly."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-22","level":"mid","profession":"operator","title":"The stance on the capacity question","scenario":"The regional manager asks whether the site can hit a 20% volume increase next year with current infrastructure. You have a view — no, not without the second sortation line — but your draft dances around it.","task":"Rewrite stating your clear answer and the one thing that would change it.","tips":["Answer directly: not with today's infrastructure.","Name the single unlock — the second sortation line.","A clear no with a path beats a hopeful maybe."],"focus":["impact","precision"],"placeholder":"Not with today's infrastructure — we'd need the second sortation line first."},
    {"id":"presence-ops-mid-23","level":"mid","profession":"operator","title":"Own the schedule-change decision","scenario":"You've decided to move the shift-break window and are announcing it to supervisors. Your draft frames it as tentative — 'we're thinking about maybe trying' — which invites re-litigation of a decision you've made.","task":"Rewrite announcing the decision as made, with the door open only for logistics.","tips":["State it as decided: the break window moves, effective Monday.","Tentative language reopens settled decisions.","Invite input on implementation, not on whether to do it."],"focus":["impact","clarity"]},
    {"id":"presence-ops-mid-24","level":"mid","profession":"operator","title":"Present two viable options with a pick","scenario":"Leadership genuinely needs to choose between two capital paths and both are viable. Presenting them is right — but presence still ends with your recommendation, not a shrug.","task":"Write a 3-4 sentence summary of both options that closes with which you'd choose.","tips":["Lay out the two fairly and briefly.","Then commit: 'if it were mine to call, I'd take option B.'","A fair comparison plus a clear pick is the mark of presence."],"focus":["impact","structure"]},
    {"id":"presence-ops-mid-25","level":"mid","profession":"operator","title":"The confident close to the QBR","scenario":"You're closing the quarterly review. Your draft trails off with 'so, that's about it, let me know if you have questions.' A closing with presence restates the verdict, the one ask, and the next checkpoint.","task":"Write a 3-sentence close: the verdict, the decision you need, and the next milestone.","tips":["Restate the quarter's verdict so it's the last thing they hear.","Name the one decision you need from them, clearly.","End on the next checkpoint — a close that moves things forward."],"focus":["impact","structure"],"placeholder":"To close: the quarter landed on plan, I need sign-off on the second line, and we'll review peak readiness in six weeks."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-ops-mid-01","level":"mid","profession":"operator","title":"Answer the target question directly","scenario":"In the leadership call the director asks flatly: 'Are we going to hit today's ship target — yes or no?' Your instinct is to explain the three risks first. He asked a yes/no.","task":"Give the direct answer first in one word, then the single most relevant caveat.","tips":["Answer yes or no before anything else.","One caveat, the load-bearing one — not all three.","Explaining before answering reads as dodging."],"focus":["clarity","concision"],"placeholder":"Yes — assuming the late trailer clears by noon."},
    {"id":"pressure-ops-mid-02","level":"mid","profession":"operator","title":"The 'why is your site always the problem' jab","scenario":"On the regional call another site manager says your site is 'always the one dragging the network numbers.' It stings and it's not quite fair, but flaring up loses the room. You need specifics, not defensiveness.","task":"Write a 2-3 sentence reply that answers with data, not emotion.","tips":["Acknowledge the number if it's true, then add the context they left out.","Answer with a specific — your volume mix or the peak timing.","Composure plus a fact beats indignation every time."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-03","level":"mid","profession":"operator","title":"The honest 'I don't know' on root cause","scenario":"The director asks in the incident call what caused the line stoppage. You genuinely don't know yet — the teardown isn't done. The temptation is to guess to look in control.","task":"Write a 2-sentence answer that admits you don't yet know, with a path and a time.","tips":["Say plainly you don't know the cause yet — guessing wrong is worse.","Give the path: teardown underway, findings by end of shift.","'I don't know, and here's how I'll know' is a strong answer, not a weak one."],"focus":["clarity","precision"],"placeholder":"I don't have the root cause yet — teardown's underway and I'll have it by end of shift."},
    {"id":"pressure-ops-mid-04","level":"mid","profession":"operator","title":"Pushback on the overtime spend","scenario":"Finance challenges you on the call: 'Your overtime is way over — what are you doing about it?' The tone is sharp. Defending yourself invites more; a specific plan closes it.","task":"Write a 2-3 sentence answer that owns the number and states the specific action.","tips":["Don't argue the number — own it, then pivot to the fix.","Name the specific action and when it takes effect.","Specifics defuse pushback; defensiveness feeds it."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-05","level":"mid","profession":"operator","title":"The customer-on-the-line question","scenario":"During the customer's site visit they ask directly: 'How do I know my orders won't be the ones that ship late?' It's a pointed question in front of your director. Deflecting looks evasive.","task":"Write a 3-sentence answer that addresses the real concern honestly, without over-promising.","tips":["Answer the actual worry, not a softened version of it.","Describe the specific safeguard for their orders.","Be honest about limits — an over-promise you break costs more than a caveat."],"focus":["clarity","audience"]},
    {"id":"pressure-ops-mid-06","level":"mid","profession":"operator","title":"'Whose fault was the miss?'","scenario":"The VP asks point-blank in front of the team who was responsible for the missed shipment. Naming a person throws them under the bus; dodging looks like you can't manage. You need to answer without scapegoating.","task":"Write a 2-3 sentence answer that takes ownership at the right level without blaming an individual.","tips":["Own it as the manager — the buck stops with you in the room.","Describe the process gap, not the person.","Save individual accountability for a private conversation, not the call."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-07","level":"mid","profession":"operator","title":"The trick question on capacity","scenario":"The regional manager asks 'so you're saying we can't grow without spending $2M?' — compressing your nuanced point into a corner. You need to answer the real question, not the loaded framing.","task":"Write a 2-3 sentence answer that reframes accurately without being cornered.","tips":["Name the framing gently, then answer the real question.","Separate what's true from the exaggeration wrapped around it.","Reframe with a fact, not a protest about being misquoted."],"focus":["clarity","precision"]},
    {"id":"pressure-ops-mid-08","level":"mid","profession":"operator","title":"Answer first, then the plan","scenario":"The director asks 'is the recalled lot fully contained?' Your draft describes the quarantine process for four sentences before confirming. The answer is yes; lead with it.","task":"Rewrite to answer yes first, then the two facts that prove it.","tips":["First word: yes.","Then the proof — count quarantined, count shipped.","Process description comes only if they ask for it."],"focus":["concision","clarity"],"placeholder":"Yes — 340 cases quarantined, zero shipped."},
    {"id":"pressure-ops-mid-09","level":"mid","profession":"operator","title":"The hostile safety question in the town hall","scenario":"In the all-hands an associate challenges you: 'You talk about safety but you push us to hit numbers no matter what — which is it?' It's confrontational and the room is watching.","task":"Write a 3-4 sentence answer that takes the challenge seriously without getting defensive.","tips":["Acknowledge the tension is real — don't pretend it isn't.","Answer the actual question: where safety and output collide, safety wins, and here's how.","Give a concrete example so it's not just a slogan."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-10","level":"mid","profession":"operator","title":"The 'when exactly' pin-down","scenario":"The director keeps pressing: 'Not soon — when exactly will the line be back?' You've been vague because you're unsure, but continued vagueness is now the problem.","task":"Write a 2-sentence answer giving a specific time or a specific time you'll commit to one.","tips":["Commit to a time, or to when you'll have a firm time.","'By 2 p.m. I'll know within 15 minutes' beats another 'soon.'","Under pressure, a specific you might revise beats a vague you can't be held to."],"focus":["precision","clarity"]},
    {"id":"pressure-ops-mid-11","level":"mid","profession":"operator","title":"Pushback from the union rep","scenario":"The employee rep challenges your rotating-weekend proposal on the spot: 'This just dumps the worst shifts on the newest people.' It's a fair concern raised sharply. You need to engage the substance.","task":"Write a 3-sentence reply that addresses the fairness point with a specific mechanism.","tips":["Don't dismiss the concern — it's legitimate.","Answer with the specific fairness mechanism in the proposal.","If they've found a real gap, say you'll fix it — don't defend a flaw."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-12","level":"mid","profession":"operator","title":"The 'did you know this would happen' question","scenario":"After the corrugate stockout, the VP asks whether you saw it coming. You had some warning signs but didn't act fast enough. The honest answer is uncomfortable but dodging is worse.","task":"Write a 2-3 sentence honest answer that owns what you missed without over-apologizing.","tips":["Answer honestly — yes, there were signs, and here's what I missed.","Own it once, cleanly, without a spiral of apology.","Pivot to what changes so it doesn't recur."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-13","level":"mid","profession":"operator","title":"The rapid-fire numbers question","scenario":"The regional VP fires: 'What's your on-time, your OEE, and your overtime this week?' You know two cold and are unsure of the third. Bluffing the third is tempting and dangerous.","task":"Write a reply that gives the two you're sure of and handles the third honestly.","tips":["Give the two solid numbers plainly.","For the third, say you'll confirm rather than guess — a wrong number costs trust.","Precision on what you know beats false confidence on what you don't."],"focus":["precision","clarity"]},
    {"id":"pressure-ops-mid-14","level":"mid","profession":"operator","title":"The leading question from the customer","scenario":"The customer asks 'so you can guarantee 100% on-time from now on, right?' It's a trap — you can't, and saying yes will haunt you. But a flat no damages the relationship.","task":"Write a 2-3 sentence answer that's honest about limits while conveying commitment.","tips":["Don't accept the impossible standard — you'll own the breach later.","Commit to what you can: the specific improvement and the safeguard.","Honest commitment reassures more than a promise you'll break."],"focus":["clarity","audience"]},
    {"id":"pressure-ops-mid-15","level":"mid","profession":"operator","title":"Answer the question, not the one you prepped","scenario":"You prepared to talk about output recovery, but the director asks about the safety near-miss instead. Your instinct is to steer back to your prepared point. Answer what was actually asked.","task":"Write a 2-3 sentence answer to the safety question, setting aside your prepared material.","tips":["Answer the question asked, not the one you wanted.","Steering to your script signals you're not really listening.","You can bridge to output after — but only after you've answered."],"focus":["clarity","audience"]},
    {"id":"pressure-ops-mid-16","level":"mid","profession":"operator","title":"The challenge to your headcount case","scenario":"The regional manager pushes back: 'Every site says they need more people — why should yours get it over the others?' It's a fair competitive challenge. Emotion won't win it; a specific differentiator will.","task":"Write a 2-3 sentence answer that differentiates your case with a specific number.","tips":["Don't plead — differentiate with a number others can't match.","Name your specific volume-per-head or the SLA at stake.","A comparative fact wins the allocation, not a stronger plea."],"focus":["precision","impact"]},
    {"id":"pressure-ops-mid-17","level":"mid","profession":"operator","title":"The 'is it safe, yes or no' from the director","scenario":"After the spill the director asks bluntly whether the dock is safe to reopen. You believe it is with one condition. He wants a clear answer, not a hedge that leaves him exposed.","task":"Write a 2-sentence answer that gives a clear yes-with-condition, no waffling.","tips":["Answer clearly: yes, once the cordon stays up till the floor's tested.","State the condition as a condition, not a hedge.","Clarity on safety is non-negotiable — the director must be able to act on your word."],"focus":["clarity","precision"],"placeholder":"Yes, safe to reopen — with the aisle cordoned until the floor test clears at noon."},
    {"id":"pressure-ops-mid-18","level":"mid","profession":"operator","title":"The blame deflected onto you","scenario":"In the cross-site call, the other site tries to pin the coordination failure entirely on your team. Some of it is yours, some isn't. You need to accept your part without absorbing theirs.","task":"Write a 2-3 sentence reply that owns your share and factually separates theirs.","tips":["Own your part first — it disarms and buys credibility.","Then separate the rest with facts, not counter-accusation.","Accepting everything is as unhelpful as accepting nothing."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-19","level":"mid","profession":"operator","title":"The 'why should we believe it'll work' doubt","scenario":"Presenting the pick-path rollout, a skeptical leader asks why they should trust the pilot will scale. Your prep was on benefits; you need to answer the doubt about scaling directly.","task":"Write a 2-3 sentence answer that addresses the scaling doubt with evidence.","tips":["Answer the doubt, don't repeat the benefits.","Give the evidence for scaling — the pilot spanned both shifts, not one.","Name the one risk to scaling and how you'll watch it — honesty earns trust."],"focus":["clarity","precision"]},
    {"id":"pressure-ops-mid-20","level":"mid","profession":"operator","title":"The vendor's cornering question","scenario":"In the negotiation the vendor asks 'are you saying you'll walk if we don't hold the price?' You have leverage but overplaying it backfires. You need to answer without bluffing or caving.","task":"Write a 2-3 sentence answer that's firm and honest without a bluff you can't back.","tips":["Don't bluff a threat you won't execute — they'll call it.","State your position honestly: the price matters, here's why, here's the range.","Firmness with a real reason beats bravado."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-mid-21","level":"mid","profession":"operator","title":"The surprise metric on the call","scenario":"The VP brings up a metric you weren't expecting — your dock turnaround time — and asks why it's slipped. You have a partial idea but not the full picture. Winging a full explanation risks being wrong.","task":"Write a 2-3 sentence answer that shares what you know and commits to the rest.","tips":["Share the part you're confident about honestly.","For the unknown part, commit to coming back — don't invent a cause.","'Here's what I know, here's what I'll confirm' is a credible answer."],"focus":["clarity","precision"]},
    {"id":"pressure-ops-mid-22","level":"mid","profession":"operator","title":"The emotional escalation from a supervisor","scenario":"In the huddle a frustrated supervisor raises their voice about the new procedure being 'impossible.' The crew is watching. Matching their heat loses the room; ignoring it loses their trust.","task":"Write a 2-3 sentence response that de-escalates and addresses the substance.","tips":["Lower the temperature before addressing the content.","Take the substantive complaint seriously — ask for the specific pain point.","Answer the real problem, not the tone it arrived in."],"focus":["clarity","audience"]},
    {"id":"pressure-ops-mid-23","level":"mid","profession":"operator","title":"The 'guarantee it won't happen again'","scenario":"After the quality escape the customer demands you guarantee it will never recur. You can't guarantee 'never,' but you can describe robust controls. A false guarantee will be thrown back at you.","task":"Write a 2-3 sentence answer that describes the concrete controls without promising the impossible.","tips":["Don't promise 'never' — describe what makes recurrence far less likely.","Name the specific new control you've added.","Credibility comes from concrete measures, not absolute promises."],"focus":["clarity","precision"]},
    {"id":"pressure-ops-mid-24","level":"mid","profession":"operator","title":"The put-on-the-spot decision","scenario":"Mid-meeting the director asks you to decide, right now, whether to pull the whole lot or just the flagged pallets. You'd rather check more, but a decision is needed. Deferring endlessly isn't an option.","task":"Write a 2-3 sentence answer that makes a defensible call with your reasoning.","tips":["Make the call — indecision under pressure is itself a failure.","State the reasoning so it's defensible even if you'd revise with more time.","If you need one fact to decide, name it and decide provisionally."],"focus":["clarity","impact"],"placeholder":"Pull the full lot — the labeling defect could span more than the flagged pallets, and the cost of being wrong the other way is a customer complaint."},
    {"id":"pressure-ops-mid-25","level":"mid","profession":"operator","title":"The compound question from the board rep","scenario":"A board rep on the site tour asks a three-part question in one breath: how's safety, are you ready for peak, and what keeps you up at night. You need to answer all three cleanly, not blur them.","task":"Write a reply that answers each of the three parts distinctly and briefly.","tips":["Signal you'll take them in turn — one, two, three.","Answer each in a sentence; don't let them bleed together.","The third — what worries you — deserves an honest specific, not a polished non-answer."],"focus":["structure","clarity"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-ops-mid-01","level":"mid","profession":"operator","title":"The before-and-after for the second line","scenario":"You're making the case for a second sortation line to regional leadership. Your draft lists the equipment specs. What persuades is the contrast: where the site is stuck today versus where it could be, made concrete.","task":"Write a 3-4 sentence case that frames the before state, the change, and the after state.","tips":["Paint 'before' vividly — the daily bottleneck people feel.","The line is the turning point between before and after.","Make 'after' concrete: the specific throughput and overtime freed."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-02","level":"mid","profession":"operator","title":"Make the safety stakes concrete","scenario":"You're persuading the crew to actually lock out equipment before clearing jams. Your draft cites the procedure. What moves people is a concrete stake — what a hand caught in a running baler actually means.","task":"Write a 3-4 sentence appeal that makes the stake real without being gratuitous.","tips":["Trade the abstract 'safety risk' for the concrete human consequence.","Keep it real, not lurid — the truth is enough.","Tie it to them: this is your hand, your shift, your family waiting."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-03","level":"mid","profession":"operator","title":"Pre-empt the cost objection","scenario":"You're proposing the $6,400 spare motor to the director, who will immediately object to spending. The strongest pitch names that objection first and dismantles it before they raise it.","task":"Write a 3-4 sentence pitch that pre-empts the cost objection with the downtime math.","tips":["Name the objection out loud: 'the $6,400 feels like a lot to sit on a shelf.'","Answer it before they voice it — one failure without it costs double.","Pre-empting an objection is more persuasive than waiting to rebut it."],"focus":["impact","precision"],"placeholder":"I know $6,400 sitting on a shelf is a hard sell — but one failure without it costs us twice that in a single day."},
    {"id":"narrative-ops-mid-04","level":"mid","profession":"operator","title":"The rollout story for the floor","scenario":"You're introducing the new cycle-count procedure and want the crew to buy in, not just comply. A dry list of steps gets compliance; a short narrative — why the old way hurt them — gets buy-in.","task":"Write a 3-4 sentence narrative that frames why the change helps them, not just the numbers.","tips":["Start from the pain they know: the month-end scramble the old way caused.","Show the change as relief from that pain, not a new burden.","Buy-in comes from a story they recognize, not a procedure they're handed."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-05","level":"mid","profession":"operator","title":"Persuade the sister site to take overflow","scenario":"You need the sister DC to absorb your overflow during dock resurfacing, which costs them effort for your benefit. A demand won't land; a story of mutual benefit and reciprocity will.","task":"Write a 3-4 sentence ask that frames the mutual benefit, not just your need.","tips":["Frame it as partnership, not a favor extracted.","Name what's in it for them — reciprocity when they need it.","Make the temporary nature and the payback explicit."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-06","level":"mid","profession":"operator","title":"The change-story for the layout redesign","scenario":"You're pitching the pack-station reconfiguration to the crew who'll have to relearn their stations. Change fatigue is real. You need a narrative that makes the disruption feel worth it.","task":"Write a 3-4 sentence pitch: the frustration today, the change, the better day after.","tips":["Acknowledge the disruption honestly — don't pretend it's painless.","Anchor on the daily frustration the redesign removes: the walking.","End on the concrete better day: less walking, more picks, same effort."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-07","level":"mid","profession":"operator","title":"Pre-empt the 'we tried this before' objection","scenario":"You're proposing a new inbound scheduling approach, and the veteran supervisors will say 'we tried something like this and it failed.' Ignoring that history dooms the pitch. Naming it disarms it.","task":"Write a 3-4 sentence pitch that names the past failure and explains what's different now.","tips":["Raise the old failure yourself — it shows you did your homework.","Explain specifically what's different this time.","Honoring the history earns you the room's trust to try again."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-08","level":"mid","profession":"operator","title":"Make the shrink number tell a story","scenario":"You're presenting shrink losses to leadership and the number alone doesn't move anyone. A narrative — where the money is quietly walking out, and what closing it would fund — makes it land.","task":"Write a 3-4 sentence narrative that turns the shrink figure into a concrete story with stakes.","tips":["Give the loss a concrete shape — what it equals in real terms.","Trace where it's going so it's a story, not a statistic.","End with what recovering it enables — make the upside vivid."],"focus":["impact","precision"]},
    {"id":"narrative-ops-mid-09","level":"mid","profession":"operator","title":"The persuasive case for the schedule change","scenario":"You're asking the crew to accept an earlier start time. They'll resist. A flat announcement breeds resentment; a narrative of why — and what they gain — builds acceptance.","task":"Write a 3-4 sentence case that frames what the earlier start makes possible for them.","tips":["Name the reason honestly: catching the earlier carrier window.","Find the genuine upside for them — earlier finish, steadier hours.","Don't oversell; one real benefit beats three hollow ones."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-10","level":"mid","profession":"operator","title":"Pre-empt the union's fairness objection","scenario":"Your rotating-weekend proposal will draw a fairness objection from the reps. The persuasive move is to build the fairness answer into the proposal itself, before they can frame it as unfair.","task":"Write a 3-4 sentence proposal that pre-empts the fairness concern in its design.","tips":["Anticipate the objection and answer it in the structure of the proposal.","Show the rotation applies evenly, with the mechanism.","Naming the concern first signals you took it seriously — that earns goodwill."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-11","level":"mid","profession":"operator","title":"The turnaround narrative for the QBR","scenario":"Your site recovered from a rough quarter and you're presenting to regional leadership. A list of monthly numbers is forgettable; a turnaround arc — the low point, the intervention, the recovery — sticks.","task":"Write a 3-4 sentence turnaround narrative anchored to the numbers.","tips":["Set the low point honestly — the arc needs a real bottom.","Name the intervention as the turning point.","Land the recovery with the number that proves it — story plus proof."],"focus":["impact","structure"],"placeholder":"In April we were at 91% on-time and slipping."},
    {"id":"narrative-ops-mid-12","level":"mid","profession":"operator","title":"Make the vendor case compelling","scenario":"You're persuading the corrugate vendor to hold their price. A flat 'please don't raise it' fails. A narrative — you've grown their volume, you're a partner worth keeping — reframes the ask.","task":"Write a 3-4 sentence pitch that frames the relationship, not just the request.","tips":["Frame the shared history and the growth you've given them.","Make holding the price a good business decision for them, not a favor.","Pre-empt their cost pressure by naming it and offering the volume trade."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-13","level":"mid","profession":"operator","title":"The stakes of the deferred maintenance","scenario":"You're arguing to fund maintenance you've been deferring. 'It might break' is abstract. 'When it breaks in week 3 of peak, here's the day we lose' makes the stake concrete and urgent.","task":"Write a 3-4 sentence case that makes the consequence of deferring concrete and timed.","tips":["Trade 'might break' for a concrete failure scenario with timing.","Put it at the worst possible moment — peak — to make the stake real.","Quantify the lost day so the abstract risk becomes a number."],"focus":["impact","precision"]},
    {"id":"narrative-ops-mid-14","level":"mid","profession":"operator","title":"Persuade IT to prioritize the scanner fix","scenario":"IT keeps deprioritizing your scanner dead-zone ticket. A ticket is a task in a queue; a narrative — the pickers losing 20 picks an hour, the compounding cost — makes it a priority.","task":"Write a 3-4 sentence case that turns the ticket into a story with a cost IT can't ignore.","tips":["Make the impact vivid: what the picker experiences every hour.","Quantify the compounding cost across shifts and weeks.","Show why waiting is more expensive than fixing — that reprioritizes."],"focus":["impact","precision"]},
    {"id":"narrative-ops-mid-15","level":"mid","profession":"operator","title":"The pilot-to-rollout persuasion","scenario":"The pilot worked and you want the go-ahead for a full rollout. Data alone leaves leadership cautious. A narrative — the problem it solved, the proof it works, the cost of not scaling — moves them to yes.","task":"Write a 3-4 sentence persuasive case: the problem, the proven fix, the cost of waiting.","tips":["Open with the problem the pilot solved, concretely.","Present the result as proof, not just a number.","End with the cost of not rolling out — inaction has a price too."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-16","level":"mid","profession":"operator","title":"Pre-empt the 'why now' on the CapEx","scenario":"Your $85k labeling-station request will draw 'why not next year?' The persuasive pitch answers that timing objection before it's asked, tying urgency to peak.","task":"Write a 3-4 sentence pitch that pre-empts the timing objection with a hard deadline.","tips":["Name the 'why now' question and answer it head-on.","Tie the urgency to a real deadline — installed and proven before peak.","Show that waiting a year means missing the window that makes it pay."],"focus":["impact","precision"]},
    {"id":"narrative-ops-mid-17","level":"mid","profession":"operator","title":"The safety-culture story for the town hall","scenario":"You want to shift how the site thinks about near-misses — from hiding them to reporting them. A policy statement won't change culture. A story — a near-miss that was reported and prevented harm — will.","task":"Write a 3-4 sentence narrative that makes reporting near-misses feel like the strong choice.","tips":["Tell a concrete story where reporting prevented a real injury.","Frame reporting as courage, not confession.","Make the hero the person who spoke up — that's the culture you want."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-18","level":"mid","profession":"operator","title":"Persuade regional to fund the training","scenario":"You want budget for cross-training so the site isn't fragile to absences. 'It would be nice' won't get funded. A narrative — the day a single call-off stopped a line, and how training prevents it — will.","task":"Write a 3-4 sentence case anchored in a concrete failure the training would prevent.","tips":["Open with the real day a single absence hurt output.","Frame training as insurance against that recurring, quantified.","Make the ROI a story: this specific pain, prevented, this often."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-19","level":"mid","profession":"operator","title":"Pre-empt the 'it'll slow us down' fear","scenario":"You're introducing a new quality-check step and the crew's objection will be that it slows the line. The persuasive move names that fear and shows why the check is faster than the rework it prevents.","task":"Write a 3-4 sentence pitch that pre-empts the speed objection with the rework math.","tips":["Say the fear out loud: 'this feels like it'll slow us down.'","Answer with the rework the check prevents — a rejected pallet costs more time.","A pre-empted objection lands as understanding, not defensiveness."],"focus":["impact","audience"],"placeholder":"I know a new check sounds like it slows the line — but one rejected pallet costs us more time than a full shift of checks."},
    {"id":"narrative-ops-mid-20","level":"mid","profession":"operator","title":"The staffing case with a human arc","scenario":"You're making the headcount case to regional leadership. Numbers alone read as one more site pleading. A narrative — the crew running hot, the overtime creeping, the burnout risk — gives the numbers weight.","task":"Write a 3-4 sentence case that pairs the staffing numbers with the human story behind them.","tips":["Let the numbers carry the logic and the story carry the urgency.","Make the burnout risk concrete — turnover, the cost of losing trained people.","Frame the ask as protecting a working system, not fixing a broken one."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-21","level":"mid","profession":"operator","title":"Persuade the crew to adopt the hourly board","scenario":"The crew fears the new hourly performance board is surveillance. To win adoption you need a narrative that reframes it — as the thing that finally sends help when a zone falls behind.","task":"Write a 3-4 sentence narrative that reframes the board from watching to helping.","tips":["Name the fear directly and set it aside honestly.","Tell the before-and-after: the shift where help came too late, and won't again.","Make the board the crew's ally, with a concrete example."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-22","level":"mid","profession":"operator","title":"Pre-empt the automation-fear objection","scenario":"You're announcing an autonomous-forklift pilot. The crew's real objection — 'are our jobs next?' — will sink the pitch if unaddressed. Naming and answering it honestly is the only persuasive path.","task":"Write a 3-4 sentence pitch that pre-empts the job-loss fear honestly.","tips":["Address the fear first — everything else is noise until you do.","Be honest about what is and isn't decided; don't over-promise.","Frame the pilot as freeing them from the worst tasks, if that's true."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-23","level":"mid","profession":"operator","title":"The compelling case against the corporate mandate","scenario":"Corporate wants a procedure that will hurt your site, and you're persuading them to grant an exception. A complaint fails; a narrative — the specific harm at your site, the alternative that meets their goal — persuades.","task":"Write a 3-4 sentence case that acknowledges corporate's goal and offers a better path.","tips":["Start by affirming the goal corporate is trying to reach.","Show the specific, concrete harm the standard procedure causes here.","Offer an alternative that hits their goal — persuasion needs a yes-able ask."],"focus":["impact","structure"]},
    {"id":"narrative-ops-mid-24","level":"mid","profession":"operator","title":"Make the peak plan inspiring, not just correct","scenario":"You're rallying the crew before peak. A logistics briefing is accurate but flat. What gets a team through peak is a narrative — the challenge, the plan, the reason it's winnable.","task":"Write a 3-4 sentence rally that frames peak as a hard but winnable challenge.","tips":["Name the challenge honestly — respect the crew by not sugarcoating it.","Give the plan as the reason it's winnable, not just a schedule.","End on shared stakes and pride — why finishing strong matters to them."],"focus":["impact","audience"]},
    {"id":"narrative-ops-mid-25","level":"mid","profession":"operator","title":"The full persuasive proposal","scenario":"You're writing the single most important proposal of the quarter to regional leadership — funding the second line. You need before/after framing, concrete stakes, and the strongest objection pre-empted, all in one tight piece.","task":"Write a 5-6 sentence proposal integrating the change frame, the stakes, and the pre-empted objection.","tips":["Frame before and after so the change is the turning point.","Make the stakes concrete with a number and a peak-season scenario.","Pre-empt the strongest objection — cost or timing — before they raise it."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-ops-mid-01","level":"mid","profession":"operator","title":"Tell the director you'll miss the target","scenario":"You know by 10 a.m. you won't hit today's ship target. Your draft eases in with everything that went well before the bad news. Clear is kind — the director needs the miss up front to react.","task":"Write a 2-3 sentence message that front-loads the miss, then the recovery.","tips":["Lead with the bad news — burying it wastes the director's reaction time.","State the size of the miss plainly.","Then the recovery plan — bad news with a path is manageable."],"focus":["clarity","impact"],"placeholder":"We'll miss today's target by about 200 cases."},
    {"id":"hard-ops-mid-02","level":"mid","profession":"operator","title":"The clean no to the overtime request","scenario":"A supervisor asks to run weekend overtime you can't approve — the budget's spent and the volume doesn't justify it. Your draft is a maze of soft maybes that leaves them thinking it's still possible.","task":"Write a 2-3 sentence response that says no clearly, with the reason.","tips":["Say no plainly — a soft no is crueler because it leaves false hope.","Give the honest reason so it doesn't feel arbitrary.","Offer the alternative if there is one; don't dangle a maybe if there isn't."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-03","level":"mid","profession":"operator","title":"Behavior, impact, ask on the missed sign-offs","scenario":"A supervisor keeps skipping the daily cycle-count sign-off. You need to address it. Your draft either scolds vaguely or avoids the specifics. The clean form is behavior, impact, then ask.","task":"Write a 3-4 sentence feedback message using behavior, impact, ask.","tips":["Name the specific behavior, not a character trait: the sign-offs were missed three days.","State the impact concretely: the count discrepancy went unflagged.","End with a clear ask and offer to help remove any blocker."],"focus":["clarity","structure"]},
    {"id":"hard-ops-mid-04","level":"mid","profession":"operator","title":"Deliver the layoff news to the shift","scenario":"You have to tell your shift that two temp positions won't be renewed after peak. Your draft hides the news in the fourth paragraph after reassurances. People deserve to hear it clearly and early.","task":"Write a 3-4 sentence message that delivers the news directly and humanely.","tips":["Front-load the news — hiding it in reassurance is unkind.","Be direct but human; acknowledge the impact on real people.","Give the facts they need: who, when, and what support exists."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-05","level":"mid","profession":"operator","title":"Tell the customer their order slips","scenario":"A key customer's order will ship two days late after the line stoppage. Your draft to the account team pads with apology and context before the date. They need the new date first to manage the customer.","task":"Write a 2-3 sentence message that leads with the new date, then the cause and fix.","tips":["The new ship date is the fact they need — lead with it.","Cause in one clause, only to help them explain it.","End with what's being done so they can reassure, not just relay bad news."],"focus":["clarity","concision"],"placeholder":"Order 88412 now ships Thursday, delivering Monday."},
    {"id":"hard-ops-mid-06","level":"mid","profession":"operator","title":"The hard conversation about attendance","scenario":"An associate's attendance has crossed the policy threshold and you need to have the formal conversation. Your draft is either harsh or so soft the seriousness doesn't land. Clarity here is the kindness.","task":"Write the 3-4 sentence opening that states the issue and the stakes clearly and respectfully.","tips":["State the factual attendance record without editorializing.","Be clear about where this sits in the process and what's at stake.","Respectful and clear aren't opposites — vagueness here would be the cruelty."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-07","level":"mid","profession":"operator","title":"Tell regional the project slipped","scenario":"The layout project slipped two weeks and you have to tell the regional manager, who championed it. Your draft opens with achievements to cushion the slip. The slip is the news; lead with it.","task":"Write a 2-3 sentence message that states the slip and new date first.","tips":["Front-load the new date — that's the decision-relevant fact.","One clause on the cause, not a defense.","Say what's protected — peak readiness is unaffected — to contain the alarm."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-08","level":"mid","profession":"operator","title":"The no to the sister site's request","scenario":"A peer site manager asks you to take overflow you genuinely can't handle. Your draft dances around it to preserve the relationship, which just prolongs their false hope and hurts your credibility.","task":"Write a 2-3 sentence response that declines clearly and offers what you can.","tips":["Give the clean no early — it respects their planning.","State the honest constraint so it's not personal.","Offer the partial help you can genuinely give."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-09","level":"mid","profession":"operator","title":"Behavior-impact-ask for the safety shortcut","scenario":"You saw an experienced operator skip the lockout step to save time. You need to address it directly — this is serious. Vague hinting won't do; the behavior, its impact, and the ask must be explicit.","task":"Write a 3-4 sentence conversation opener: behavior, impact, ask.","tips":["Name exactly what you saw — no euphemisms for a safety violation.","State the impact starkly: this is how people lose hands.","The ask is non-negotiable here — lock out, every time, no exceptions."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-10","level":"mid","profession":"operator","title":"Tell the crew the bonus target was missed","scenario":"The site missed the quarterly bonus threshold and the crew won't get the payout they hoped for. Your draft buries it under praise. They'll hear it either way — better clearly and honestly from you.","task":"Write a 3-4 sentence message that delivers the miss honestly, then the path forward.","tips":["Deliver the news plainly — they'll respect the honesty.","Acknowledge the disappointment; don't paper over it with praise.","Show the path to next quarter's threshold — concrete, not cheerleading."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-11","level":"mid","profession":"operator","title":"The overrun you have to report","scenario":"Maintenance will close $18k over budget and you must tell your director before finance does. Your draft cushions with how well the rest tracks. The overrun is the message; lead with it.","task":"Write a 2-3 sentence heads-up that states the overrun first, then the cause and plan.","tips":["Lead with the number — the director must not learn it from finance.","Cause in one clause: two one-time motor failures.","End with what you're doing so the news arrives with a plan."],"focus":["clarity","impact"],"placeholder":"Heads-up before finance's pack: maintenance will close about $18k over."},
    {"id":"hard-ops-mid-12","level":"mid","profession":"operator","title":"The performance message to a struggling supervisor","scenario":"A supervisor you like is underperforming and you've been avoiding the conversation out of discomfort. Your draft is so gentle the actual message is invisible. Clarity is the respect this person is owed.","task":"Write the 3-4 sentence core message: the gap, the specific examples, and the expectation.","tips":["State the performance gap directly — avoidance isn't kindness.","Ground it in specific examples, not a general impression.","Set a clear expectation and offer support — clear is kind."],"focus":["clarity","structure"]},
    {"id":"hard-ops-mid-13","level":"mid","profession":"operator","title":"Tell the vendor you're ending the contract","scenario":"After repeated quality failures you're ending the pallet supplier's contract. Your draft is evasive to avoid conflict, which risks a messy exit. A clear, factual, professional message serves both sides.","task":"Write a 3-4 sentence message that delivers the decision clearly and professionally.","tips":["State the decision plainly — evasion prolongs and worsens the exit.","Ground it in the factual record, not grievance.","Keep it professional; you may cross paths again."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-14","level":"mid","profession":"operator","title":"The no to corporate's timeline","scenario":"Corporate wants the new WMS module live in two weeks and you know it's not safe to rush. Your draft hedges toward compliance you can't deliver. A clear, reasoned no now beats a failed rollout later.","task":"Write a 2-3 sentence response that declines the timeline with the reason and an alternative.","tips":["Say the timeline isn't achievable safely — clearly, not apologetically.","Give the concrete reason a rushed go-live fails.","Offer the date you can hit — a no with a yes attached."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-15","level":"mid","profession":"operator","title":"Deliver the demotion decision","scenario":"You've decided to move a team lead back to an associate role after a sustained performance issue. This is a hard, personal conversation. Your draft avoids the actual decision until the end.","task":"Write the 3-4 sentence opening that states the decision clearly and with dignity.","tips":["State the decision early — dragging it out is agonizing for both.","Be factual about the why; this isn't the moment to relitigate.","Preserve their dignity — clear delivery and respect coexist."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-16","level":"mid","profession":"operator","title":"Tell leadership the safety incident happened","scenario":"A recordable injury occurred on your shift and you must report it up. Your draft opens with mitigating context, which reads as minimizing. The incident comes first; context follows.","task":"Write a 2-3 sentence report that states what happened first, then the response.","tips":["Lead with the incident — front-loading context looks like spin.","State the facts plainly: what, who, current condition.","Then the response and containment — no defensiveness."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-17","level":"mid","profession":"operator","title":"The behavior-impact-ask for chronic lateness","scenario":"A supervisor consistently arrives after their crew, leaving the shift start uncovered. You need to address it cleanly. Your draft either avoids it or attacks; the structured form keeps it fair.","task":"Write a 3-4 sentence message: the behavior, its impact on the shift, and the ask.","tips":["Behavior: arriving after the crew, specific days.","Impact: the shift starts without direction, and it shows in the first hour.","Ask: be on the floor before the crew, and tell me if something's blocking that."],"focus":["clarity","structure"]},
    {"id":"hard-ops-mid-18","level":"mid","profession":"operator","title":"Tell the crew about the pay-freeze","scenario":"You have to relay that annual raises are frozen this year. Your draft spins it positively, which the crew will see through and resent. Straight, honest delivery — with what you can offer — respects them more.","task":"Write a 3-4 sentence message that delivers the freeze honestly without spin.","tips":["Deliver it straight — spin insults their intelligence.","Acknowledge it's not what anyone wanted to hear.","Be clear about what you can do, even if small — honesty over cheerleading."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-19","level":"mid","profession":"operator","title":"The no to a good idea you can't fund","scenario":"An associate proposed a genuinely good improvement, but there's no budget this year. Your draft is so apologetic it obscures the answer. Respect the effort with a clear no and a real reason.","task":"Write a 2-3 sentence response that declines clearly while honoring the idea.","tips":["Acknowledge the idea's merit specifically — it was a good one.","Give the clean no and the honest constraint.","Leave a door — revisit next budget cycle — if it's real, not a brush-off."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-20","level":"mid","profession":"operator","title":"Tell the director the recovery failed","scenario":"You promised the overtime plan would clear the backlog by Monday and it didn't. You have to tell the director your plan fell short. Your draft avoids owning the failure. Clear ownership rebuilds trust.","task":"Write a 2-3 sentence message that owns the failure and states the revised plan.","tips":["Own it directly — 'my plan didn't clear it' — no deflection.","State the new reality: where the backlog actually stands.","Give the revised plan; a failure with a next step is recoverable."],"focus":["clarity","impact"],"placeholder":"My weekend plan fell short — we cleared 2,000 of the 3,000, not all of it."},
    {"id":"hard-ops-mid-21","level":"mid","profession":"operator","title":"The escalation about a peer manager","scenario":"A peer manager at another site keeps missing the handoffs that stall your inbound, and you need to raise it with your shared regional manager. Your draft is either a complaint or too vague to act on.","task":"Write a 3-4 sentence escalation that's factual about the pattern and constructive.","tips":["State the pattern with dated specifics, not frustration.","Focus on the operational impact, not the personality.","Propose the fix you want — escalation should seek resolution, not just vent."],"focus":["clarity","structure"]},
    {"id":"hard-ops-mid-22","level":"mid","profession":"operator","title":"Deliver the quality-hold news to the customer","scenario":"You've had to hold a lot destined for a key customer, and their order will be short this week. Your draft over-apologizes and under-informs. They need the facts to plan, delivered directly.","task":"Write a 3-4 sentence message that states the shortfall, the reason, and the recovery date.","tips":["Lead with the concrete impact: their order is short by this much.","Give the honest reason briefly — a quality hold, which protects them.","End with the recovery date so they can plan around it."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-23","level":"mid","profession":"operator","title":"The hard feedback to a high performer","scenario":"Your best supervisor is excellent operationally but has been dismissive with the crew, and morale is slipping. Praising them makes the feedback easy to dismiss; you need the behavior addressed clearly.","task":"Write a 3-4 sentence message using behavior, impact, ask, without letting praise dilute it.","tips":["Don't cushion so much the message vanishes — high performers still need it clear.","Behavior: the specific dismissive interactions.","Impact: morale and retention in their team; then the direct ask."],"focus":["clarity","structure"]},
    {"id":"hard-ops-mid-24","level":"mid","profession":"operator","title":"Tell regional you can't hit the growth number","scenario":"Regional set a volume growth target for your site that your infrastructure can't support. Rather than fail quietly at year-end, you're saying so now. Your draft hedges; the honest, early no is the right call.","task":"Write a 2-3 sentence message that states clearly you can't hit it as-is, with the reason.","tips":["Say it plainly now — silence until year-end is the real failure.","Give the specific constraint that caps the number.","Name what would change it — the honest no with a path forward."],"focus":["clarity","impact"]},
    {"id":"hard-ops-mid-25","level":"mid","profession":"operator","title":"The full hard-message memo","scenario":"You must tell the whole site that a planned expansion is cancelled, which affects hiring plans people were counting on. This needs front-loaded bad news, honest acknowledgment, and a clear picture of what's next — all with care.","task":"Write a 4-5 sentence message that front-loads the news, acknowledges the impact, and states what's next.","tips":["Front-load the decision — everyone knows the rumor; confirm it clearly.","Acknowledge the real impact on people's plans, honestly.","Be concrete about what continues and what doesn't — uncertainty is worse than bad news."],"focus":["clarity","impact"]}
  ],
  "putting-it-together": [
    {"id":"together-ops-mid-01","level":"mid","profession":"operator","title":"The full incident escalation","scenario":"Line 2 is down mid-shift, a customer order is at risk, and you're writing the escalation to the site director. You need the point up front, the right altitude, the facts precise, and a recommendation — all in a message read in fifteen seconds.","task":"Write a 3-4 sentence escalation that leads with the impact, gives the precise facts, and recommends an action.","tips":["Lead with what's at risk, not the timeline.","Facts precise — hours down, cases affected, ETA.","End owning a recommendation, not asking what to do."],"focus":["structure","impact"]},
    {"id":"together-ops-mid-02","level":"mid","profession":"operator","title":"Match the register: text vs. memo","scenario":"The same news — Saturday overtime is approved — goes as a quick text to the shift lead and a formal note to the crew. One register won't fit both channels. You need to write each to its medium.","task":"Write the one-line text to the lead and the 2-3 sentence crew note, matched to each channel.","tips":["The text is terse and immediate — the lead just needs the go.","The crew note is fuller: what, when, and how to raise conflicts.","Register is a choice — match it to channel and audience deliberately."],"focus":["audience","concision"]},
    {"id":"together-ops-mid-03","level":"mid","profession":"operator","title":"Edit the weekly report like a reader","scenario":"Your weekly report to regional leadership is drafted but bloated, buries the lead, and mixes altitudes. Before sending, you need to read it as the busy regional manager would and cut it to what they'll actually use.","task":"Rewrite the report's opening so the lead is on top, tightened to what a busy reader needs.","tips":["Read as the recipient: what do they need in the first three seconds?","Move the lead to the top; cut what's true every week.","Match the altitude — verdicts and exceptions, not floor detail."],"focus":["structure","concision"]},
    {"id":"together-ops-mid-04","level":"mid","profession":"operator","title":"The peak-readiness brief, done right","scenario":"You're presenting peak readiness to regional leadership: they want the verdict, the evidence, the risks, and your recommendation, delivered with presence in five minutes. Everything you've practiced has to come together.","task":"Write the 4-5 sentence brief: verdict first, evidence, the top risk, and your recommendation.","tips":["Open with the readiness verdict — ready, or ready-except.","Support with the evidence that earns the verdict, precise.","Name the one open risk and recommend the action to close it."],"focus":["structure","impact"],"placeholder":"We're ready for peak on nine of ten workstreams."},
    {"id":"together-ops-mid-05","level":"mid","profession":"operator","title":"The cross-site coordination message","scenario":"You're aligning three sites on a shared inbound plan. The message must lead with the ask, address three different site audiences fairly, be precise on volumes and dates, and pre-empt the obvious objection about capacity.","task":"Write a 4-5 sentence message that leads with the plan, gives each site its numbers, and pre-empts the capacity concern.","tips":["Lead with the shared plan and the one thing you need from each.","Give each site its specific volume and date — precision prevents disputes.","Pre-empt the capacity objection by naming it and the flex you've built in."],"focus":["structure","precision"]},
    {"id":"together-ops-mid-06","level":"mid","profession":"operator","title":"The vendor negotiation email","scenario":"You're writing to the corrugate vendor to hold price. It needs the ask up front, a persuasive frame built on your growing volume, precise numbers, and the strongest objection — their input costs — pre-empted, all professionally.","task":"Write a 4-5 sentence email integrating the clear ask, the volume case, and the pre-empted cost objection.","tips":["Lead with the ask: hold this year's price.","Build the case on precise volume growth, not vague partnership talk.","Pre-empt their cost-pressure objection with the trade you're offering."],"focus":["impact","precision"]},
    {"id":"together-ops-mid-07","level":"mid","profession":"operator","title":"The all-hands script that lands","scenario":"You're scripting the quarterly all-hands. It must lead with one governing message, be pitched to the floor's language, stay concise enough to hold attention, and close with presence. Every skill has to show up.","task":"Write the 4-5 sentence opening and close: one message up front, plain language, a confident close.","tips":["Open with the single message they should remember this quarter.","Use the floor's words, not corporate abstractions.","Close with presence — restate the message and what you're asking of them."],"focus":["audience","impact"]},
    {"id":"together-ops-mid-08","level":"mid","profession":"operator","title":"The board-page contribution","scenario":"You contribute the operations page to the regional board deck. It must be scannable in ten seconds: headline verdict, three supporting points, precise numbers, and your recommendation — at board altitude, not floor detail.","task":"Write the board page's top: headline verdict, three phrase-length points, and the recommendation.","tips":["One headline sentence readable in three seconds.","Three points, each a phrase with a number.","Board altitude — cut everything a board member wouldn't act on."],"focus":["structure","concision"]},
    {"id":"together-ops-mid-09","level":"mid","profession":"operator","title":"The hard message, fully assembled","scenario":"You're telling regional leadership the site missed its quarterly targets. This needs front-loaded bad news, precise numbers, an owned explanation without blame, and a credible recovery plan — delivered with composure.","task":"Write a 4-5 sentence message that front-loads the miss, is precise, owns it, and gives the recovery.","tips":["Lead with the miss and the number — no cushioning.","Own it at the manager level, no blame downward.","Close with a specific, credible recovery plan and a checkpoint."],"focus":["clarity","impact"]},
    {"id":"together-ops-mid-10","level":"mid","profession":"operator","title":"Edit the rollout announcement","scenario":"Your draft announcing the new putaway procedure is complete but wordy, buries what changes, and mixes the crew's needs with QA's. Before it goes out, edit it into something the floor can act on immediately.","task":"Rewrite the announcement: lead with what changes, cut the padding, one audience only.","tips":["Lead with the change and the date — that's the action.","Cut every sentence that doesn't help someone do their job differently.","Serve the floor only; QA's version is a separate note."],"focus":["structure","concision"]},
    {"id":"together-ops-mid-11","level":"mid","profession":"operator","title":"The KPI review under time pressure","scenario":"You have three minutes with the regional VP to review the site's KPIs. You must lead with the headline metric, translate to their altitude, be precise, and end with the one decision you need. No room for warm-up.","task":"Write the 3-4 sentence review: headline metric first, precise, ending with the decision you need.","tips":["Open with the metric that governs the week and its trend.","Precise numbers, no vague direction words.","End with the single decision you need — three minutes buys one ask."],"focus":["structure","precision"],"placeholder":"On-time ship recovered to 98% this week, three weeks of gains."},
    {"id":"together-ops-mid-12","level":"mid","profession":"operator","title":"The staffing case, fully built","scenario":"You're making the permanent-headcount case to the regional manager. It needs SCQA structure, precise numbers, a persuasive human frame, an owned recommendation, and the budget objection pre-empted — one tight page.","task":"Write a 5-6 sentence case integrating the SCQA frame, the numbers, and the pre-empted objection.","tips":["Frame with situation and complication before the ask.","Numbers precise: the volume shift and the FTE gap.","Own the recommended number and pre-empt the budget objection."],"focus":["structure","impact"]},
    {"id":"together-ops-mid-13","level":"mid","profession":"operator","title":"The customer visit talking points","scenario":"A key customer tours Friday. You need talking points that answer their real concerns in their terms, stay precise about your quality controls, handle the pointed question with composure, and project presence throughout.","task":"Write the 4-5 sentence core talking points, framed on the customer's stake and precise on controls.","tips":["Anchor everything on their stake — what reaches their shelves.","Be precise about the controls, not vaguely reassuring.","Prepare the composed answer to the pointed question in advance."],"focus":["audience","precision"]},
    {"id":"together-ops-mid-14","level":"mid","profession":"operator","title":"The shift-change communication plan","scenario":"You're rolling out an earlier shift start to the whole site. Crews, supervisors, and leadership each need a different version — right altitude, right register, right channel — but all consistent and clear.","task":"Write the crew version in 3-4 sentences and note in one line each how the supervisor and leadership versions differ.","tips":["Crew version: their new hours, date, how to flag conflicts.","Supervisor version adds what they must relay and confirm.","Leadership version is cost and coverage — same facts, different altitude."],"focus":["audience","structure"]},
    {"id":"together-ops-mid-15","level":"mid","profession":"operator","title":"The root-cause report, assembled","scenario":"After the three-hour downtime you write the full root-cause report to leadership. It needs the finding up front, clean structure separating what/why/action, precise evidence, and owned corrective actions with dates.","task":"Write a 4-5 sentence report: finding first, then structured cause and dated corrective action.","tips":["Lead with the cause — the finding is the headline.","Separate what happened, why, and the action cleanly.","Corrective actions get owners and dates, precisely."],"focus":["structure","precision"],"placeholder":"Root cause: a worn bearing the last PM missed."},
    {"id":"together-ops-mid-16","level":"mid","profession":"operator","title":"The pushback-heavy budget defense","scenario":"You're defending your maintenance budget in the regional review, expecting hard pushback on the overrun. You need to own the number, answer challenges with specifics not defensiveness, and hold your recommendation with presence.","task":"Write the 3-4 sentence defense: own the overrun, answer the likely challenge with a specific, hold the ask.","tips":["Own the overrun before they attack it.","Have the specific answer ready — the one-time driver, not a defense.","Hold your forward ask — the spare-part proposal — with presence."],"focus":["impact","precision"]},
    {"id":"together-ops-mid-17","level":"mid","profession":"operator","title":"Edit the escalation for the reader","scenario":"Your incident escalation is drafted but leads with narration, hedges the severity, and buries the ask. Before you hit send to the director at 6 a.m., edit it into what a half-awake reader can act on in one read.","task":"Rewrite so the first line is the risk and the ask, hedges gone, one read is enough.","tips":["First line: the risk and what you need — nothing before it.","Cut every hedge; state the severity plainly.","Test it: could a tired director act on the first sentence alone?"],"focus":["concision","clarity"]},
    {"id":"together-ops-mid-18","level":"mid","profession":"operator","title":"The vendor-exit letter","scenario":"You're formally ending the pallet supplier's contract. The letter must deliver the hard news clearly, be precise about the factual record, stay professional, and pre-empt a dispute — everything at once, in a document that may be read by lawyers.","task":"Write a 4-5 sentence letter that states the decision, cites the record precisely, and stays professional.","tips":["State the decision clearly and early.","Cite the specific, dated performance record — precision protects you.","Keep the tone professional; assume it will be read carefully."],"focus":["clarity","precision"]},
    {"id":"together-ops-mid-19","level":"mid","profession":"operator","title":"The town-hall Q&A under fire","scenario":"At the all-hands you take live questions, some hostile — about safety, overtime, and job security. You need to answer each question actually asked, stay composed, be precise, and project presence with the room watching.","task":"Write composed 2-3 sentence answers to two of the hostile questions, answering what's actually asked.","tips":["Answer the real question first, not a softened version.","Stay composed — the room reads your steadiness.","Be precise and honest; a specific beats a polished dodge."],"focus":["clarity","impact"]},
    {"id":"together-ops-mid-20","level":"mid","profession":"operator","title":"The CapEx proposal, complete","scenario":"You're submitting the second-line CapEx proposal to regional leadership. It must lead with the recommendation, structure the case top-down, be precise on payback, frame the before-and-after persuasively, and pre-empt the timing objection.","task":"Write a 5-6 sentence proposal: recommendation first, structured case, precise payback, pre-empted objection.","tips":["Recommendation in sentence one, owned.","Three supporting pillars, each with a precise number.","Frame before-and-after and pre-empt 'why now' with the peak deadline."],"focus":["structure","impact"]},
    {"id":"together-ops-mid-21","level":"mid","profession":"operator","title":"The multi-site status update","scenario":"You coordinate three sites on a regional project and send a weekly status. It must lead with the portfolio verdict, be signposted per site, precise on progress, and surface only exceptions — scannable and consistent every week.","task":"Write the update: one-line portfolio verdict, then a tight signposted line per site with the exception flagged.","tips":["Lead with the portfolio status — on track or the exception.","One consistent block per site, same order weekly.","Surface only what needs attention; confirm the rest in a line."],"focus":["structure","concision"]},
    {"id":"together-ops-mid-22","level":"mid","profession":"operator","title":"The difficult performance review","scenario":"You're writing a supervisor's performance review that must deliver hard feedback clearly, separate observed fact from your judgment, be precise with examples, and remain fair and actionable — a document that will be read and possibly contested.","task":"Write the 4-5 sentence core: the fact-based observations, your assessment, and the one priority to improve.","tips":["State observed behaviors with dated specifics, separate from judgment.","Frame your assessment as assessment, defensibly.","End with one priority, not five — actionable and fair."],"focus":["clarity","precision"]},
    {"id":"together-ops-mid-23","level":"mid","profession":"operator","title":"The rally before peak","scenario":"You're addressing the crew the morning peak begins. You need one clear message, framed persuasively as a hard-but-winnable challenge, in the crew's language, delivered with presence and genuine conviction.","task":"Write a 4-5 sentence rally: the challenge named honestly, the plan as the reason it's winnable, a close with conviction.","tips":["Name the challenge honestly — respect earns attention.","Give the plan as the reason it's winnable, not just a schedule.","Close with conviction and shared stakes, in their words."],"focus":["impact","audience"]},
    {"id":"together-ops-mid-24","level":"mid","profession":"operator","title":"The regional-review presentation","scenario":"You have ten minutes in the regional review to present the site's quarter. You must open with presence and a verdict, structure top-down, be precise, answer pushback composedly, and close with the decision you need — the full toolkit, live.","task":"Write the 4-5 sentence opening and close: verdict and frame up front, the decision you need at the end.","tips":["Open with the verdict and signpost the three points.","Keep the middle precise and top-down — evidence under each point.","Close with the one decision you need and the next checkpoint."],"focus":["structure","impact"],"placeholder":"The quarter landed on plan — I'll cover output, safety, and the one investment I need."},
    {"id":"together-ops-mid-25","level":"mid","profession":"operator","title":"The capstone: the crisis communication","scenario":"A major equipment failure will disrupt shipping for two days. You must, within the hour, escalate to leadership, inform the affected customers via the account team, and brief the crew — three audiences, three registers, all clear, precise, and composed under real pressure.","task":"Write the one-line director escalation, the 2-sentence account-team note, and the 2-sentence crew brief — each matched to its audience.","tips":["Director: the impact, the ETA, and your recommendation, in one line.","Account team: what customers face and the customer-safe fix, precisely.","Crew: what's happening and what you need from them, calm and clear."],"focus":["audience","impact"]}
  ],
};
